window.QUESTIONS.push(
  {"id":"sc-db-1","cat":"DB","level":"기본","q":"SQL에서 WHERE와 HAVING의 차이는 무엇인가요? GROUP BY 없이 HAVING을 쓸 수 있나요?","a":"WHERE는 그룹핑·집계 이전 단계에서 개별 행을 필터링하고, HAVING은 GROUP BY로 그룹핑·집계된 결과를 필터링합니다. 논리적 실행 순서가 FROM→WHERE→GROUP BY→HAVING→SELECT라서 HAVING에서는 집계 함수(SUM, COUNT 등)를 조건으로 쓸 수 있지만 WHERE에서는 못 씁니다. GROUP BY가 없어도 HAVING은 가능한데, 이 경우 전체 행이 하나의 그룹으로 취급되어 집계 조건을 걸 수 있습니다."},
  {"id":"sc-db-2","cat":"DB","level":"중급","q":"NOT IN 서브쿼리에 NULL이 섞이면 결과가 비어버리는 이유를 설명해 주세요.","a":"SQL의 NULL은 3-valued logic을 따르기 때문입니다. NOT IN은 내부적으로 모든 값과의 != 비교를 AND로 묶는데, NULL과의 비교는 FALSE가 아니라 UNKNOWN을 반환합니다. 따라서 서브쿼리 결과에 NULL이 하나라도 있으면 전체 조건이 절대 TRUE가 될 수 없어 모든 행이 탈락합니다. 이를 피하려면 서브쿼리에서 NULL을 제거하거나 NOT EXISTS로 바꿔 쓰는 것이 안전합니다."},
  {"id":"sc-db-3","cat":"DB","level":"기본","q":"INNER JOIN과 LEFT JOIN의 결과 행 수가 같은 경우와 다른 경우는 각각 언제인가요?","a":"왼쪽 테이블의 모든 행이 오른쪽 테이블에 매칭되는 행을 가지면 INNER와 LEFT의 결과가 같습니다. 반대로 왼쪽에는 있지만 오른쪽에 매칭이 없는 행이 존재하면 LEFT JOIN은 그 행을 오른쪽 컬럼을 NULL로 채워 보존하므로 INNER보다 행이 많아집니다. 또한 오른쪽에 매칭이 여러 건이면 INNER·LEFT 모두 그만큼 행이 증식하므로, '없는 것 찾기'는 LEFT JOIN 후 오른쪽 키가 IS NULL인 행을 거르는 방식으로 합니다."},
  {"id":"sc-db-4","cat":"DB","level":"중급","q":"PostgreSQL에서 timestamp와 timestamptz의 기본값으로 무엇을 권장하며 그 이유는 무엇인가요?","a":"timestamp(timestamp without time zone)는 타임존 정보 없이 값을 그대로 저장해 같은 문자열이 서버 위치에 따라 다른 시점을 의미할 수 있습니다. 반면 timestamptz는 입력을 UTC로 정규화해 저장하고 조회 시 세션 타임존으로 변환해 주므로, 여러 지역·서버가 얽힌 환경에서 시점을 모호함 없이 다룰 수 있습니다. 그래서 시각 컬럼은 기본적으로 timestamptz를 권장합니다."},
  {"id":"sc-db-5","cat":"DB","level":"기본","q":"PostgreSQL에서 char(n), varchar, text의 저장·성능 차이와 권장 타입은 무엇인가요?","a":"PostgreSQL에서는 세 타입의 내부 저장 방식이 사실상 동일해 성능 차이가 거의 없습니다. char(n)은 길이가 모자라면 공백으로 패딩되어 비교 시 혼란을 주고 저장 공간만 더 쓰므로 권장하지 않습니다. 길이 제한이 업무상 꼭 필요하면 varchar(n)을, 아니면 그냥 text를 쓰는 것이 일반적인 권장이며, 길이 제한도 CHECK 제약으로 표현할 수 있습니다."},
  {"id":"sc-db-6","cat":"DB","level":"중급","q":"2정규형과 3정규형의 차이를, 부분 종속과 이행 종속 개념으로 설명해 주세요.","a":"2NF는 1NF를 만족하면서 기본키가 복합키일 때 비키 속성이 기본키의 일부에만 의존하는 부분 종속(partial dependency)을 제거한 상태입니다. 3NF는 2NF에 더해 비키 속성이 다른 비키 속성을 거쳐 기본키에 의존하는 이행 종속(transitive dependency)을 제거한 상태입니다. 즉 2NF는 '키의 일부에 대한 종속'을, 3NF는 '키가 아닌 컬럼에 대한 종속'을 없애는 단계입니다."},
  {"id":"sc-db-7","cat":"DB","level":"중급","q":"반정규화를 적용할 때 치러야 하는 비용은 무엇인가요?","a":"반정규화는 데이터를 중복 저장해 조인을 줄여 읽기 성능을 높이지만, 같은 데이터가 여러 곳에 존재하므로 갱신 시 모든 사본을 함께 바꿔야 하는 갱신 이상(update anomaly)과 정합성 관리 비용이 생깁니다. 한 곳만 바뀌고 다른 곳이 누락되면 데이터가 어긋나므로, 트리거·애플리케이션 로직·배치 등으로 동기화를 보장해야 합니다. 따라서 읽기 이득이 갱신·정합성 비용을 분명히 상회할 때만 선택적으로 적용해야 합니다."},
  {"id":"sc-db-8","cat":"DB","level":"기본","q":"자연키 대신 대리키(surrogate key)를 쓰는 이유와 그 단점은 무엇인가요?","a":"대리키는 업무 의미가 없는 순번·일련번호 같은 인조 식별자라서, 업무 규칙이 바뀌어 자연키 값이 변하더라도 기본키와 외래키가 영향을 받지 않고 단순·불변·고정 크기라 인덱스·조인에 유리합니다. JPA에서는 보통 @Id @GeneratedValue로 매핑합니다. 단점은 키 자체에 업무 의미가 없어 별도 UNIQUE 제약으로 자연키 중복을 막지 않으면 의미상 중복 데이터가 들어올 수 있고, 조인 없이는 사람이 행을 식별하기 어렵다는 점입니다."},
  {"id":"sc-db-9","cat":"DB","level":"중급","q":"외래키를 DB 제약으로 관리하는 것과 애플리케이션에서만 관리하는 것의 트레이드오프는 무엇인가요?","a":"DB에 FK 제약을 두면 참조 무결성이 엔진 차원에서 보장되고 ON DELETE CASCADE/RESTRICT/SET NULL 같은 정책을 일관되게 적용할 수 있지만, 쓰기 시 검증·락 오버헤드가 생기고 대량 적재나 샤딩 환경에서는 제약이 됩니다. 앱에서만 관리하면 유연하고 성능·확장에 유리하지만, 코드 결함이나 우회 경로로 고아 데이터가 생길 위험을 개발자가 떠안습니다. 정합성이 중요한 OLTP는 DB 제약을, 초대량·분산 환경은 앱 관리를 택하는 식으로 트레이드오프합니다."},
  {"id":"sc-db-10","cat":"DB","level":"중급","q":"N:M 관계를 관계형 DB와 JPA에서 어떻게 매핑하며, @ManyToMany와 연결 엔티티는 어떤 기준으로 선택하나요?","a":"관계형 DB에서는 N:M을 두 외래키를 가진 중간(연결) 테이블로 풀어냅니다. JPA에서 조인 테이블에 부가 컬럼이 없으면 @ManyToMany + @JoinTable로 간단히 매핑할 수 있습니다. 하지만 연결 자체에 추가일·정렬순서 같은 부가 컬럼이 필요하거나 향후 필요해질 가능성이 있으면, 연결 엔티티를 별도로 만들어 @ManyToOne 두 개와 복합키로 매핑하는 것이 권장됩니다. 실무에서는 확장성 때문에 처음부터 연결 엔티티로 가는 경우가 많습니다."},
  {"id":"sc-db-11","cat":"DB","level":"중급","q":"SQLD 관점에서 3층 스키마의 각 계층과 논리적·물리적 데이터 독립성이 뜻하는 바를 설명해 주세요.","a":"3층 스키마는 외부 스키마(External, 사용자·뷰 관점), 개념 스키마(Conceptual, 전사 데이터를 통합한 ERD 관점), 내부 스키마(Internal, 물리 저장 구조)로 나뉩니다. 논리적 독립성은 개념 스키마가 바뀌어도 외부 스키마와 응용에 영향이 없도록 분리하는 것이고, 물리적 독립성은 내부 스키마(저장·인덱스 구조)가 바뀌어도 개념 스키마에 영향이 없도록 분리하는 것입니다. 즉 각 계층 변경의 파급을 차단해 유지보수성을 높이는 개념입니다."},
  {"id":"sc-db-12","cat":"DB","level":"중급","q":"SQLD에서 식별 관계와 비식별 관계의 차이, 그리고 그것이 자식의 주식별자에 미치는 영향을 설명해 주세요.","a":"식별 관계는 부모의 주식별자가 자식의 주식별자 일부로 상속되어 자식 PK에 포함되며 ERD에서 실선으로 표기하고 강한 종속을 나타냅니다. 비식별 관계는 부모의 주식별자가 자식의 일반 속성, 즉 단순 FK로만 들어가 자식 PK에는 포함되지 않으며 점선으로 표기하고 약한 종속을 나타냅니다. 식별 관계를 무분별하게 연쇄하면 부모의 키가 계속 자식 PK로 누적되어 PK 컬럼이 증식하는 문제가 생기므로 주의해야 합니다."},
  {"id":"sc-db-13","cat":"DB","level":"심화","q":"SQLD에서 주식별자가 갖춰야 할 네 가지 조건과, 본질식별자 대신 인조식별자를 선택하는 기준은 무엇인가요?","a":"주식별자는 유일성(인스턴스를 유일하게 구분), 최소성(꼭 필요한 속성으로만 구성), 불변성(값이 잘 바뀌지 않음), 존재성(NOT NULL)을 만족해야 합니다. 본질식별자는 주민번호·사업자번호처럼 업무적으로 의미 있는 자연키이고, 인조식별자는 순번·일련번호로 새로 부여한 대리키입니다. 본질식별자가 복잡하거나 변경 가능성이 있거나 외부 노출이 부담스러우면 단순·불변한 인조식별자를 쓰되, 인조식별자는 자연키 중복 방어가 약해지므로 별도 UNIQUE 제약으로 본질 키의 유일성을 보장해야 합니다."},
  {"id":"sc-db-14","cat":"DB","level":"중급","q":"B-Tree와 B+Tree의 차이는 무엇이며, DB 인덱스가 B+Tree를 쓰는 이유는 무엇인가요?","a":"B-Tree는 내부 노드와 리프 노드 모두에 데이터를 저장하는 반면, B+Tree는 실제 데이터(또는 포인터)를 리프 노드에만 두고 리프들이 정렬된 순서로 서로 연결되어 있습니다. 이 구조 덕분에 리프 연결을 따라가는 범위 스캔(range scan)이 효율적이고, 내부 노드는 키만 담아 한 페이지에 더 많은 키가 들어가므로 트리 높이가 낮아져 디스크 I/O 횟수가 줄어듭니다. 그래서 디스크 기반 DB 인덱스는 range scan과 낮은 높이가 유리한 B+Tree 계열을 사용합니다."},
  {"id":"sc-db-15","cat":"DB","level":"중급","q":"복합 인덱스 (a,b,c)가 있을 때 WHERE b=? AND c=? 조건이 인덱스를 타지 못하는 이유는 무엇인가요?","a":"복합 인덱스는 leftmost prefix 규칙을 따르기 때문입니다. (a,b,c) 인덱스는 a, (a,b), (a,b,c) 순서의 선두 컬럼부터 연속된 조건에만 정렬 효용이 있고, 선두 컬럼 a가 빠진 b·c만으로는 인덱스 정렬 순서를 활용할 수 없습니다. 인덱스는 a로 먼저 정렬된 뒤 그 안에서 b, c로 정렬된 구조라 a 없이 b를 찾으면 전체를 훑어야 하므로 인덱스를 효율적으로 타지 못합니다. (참고로 PostgreSQL은 선두 컬럼이 빠져도 조건이 충분히 선택적이면 인덱스 전체를 훑는 비효율적 Index Scan을 택할 수도 있으나, 정렬 효용을 살린 정상적 인덱스 활용은 아닙니다.) 또한 선두는 등호 조건, 마지막은 범위 조건으로 두는 것이 효율적입니다."},
  {"id":"sc-db-16","cat":"DB","level":"중급","q":"PostgreSQL의 인덱스는 클러스터드 인덱스인가요? MySQL InnoDB와의 차이를 설명해 주세요.","a":"PostgreSQL은 항상 논클러스터드입니다. 실제 행은 heap에 저장되고 인덱스는 ctid로 heap의 물리 위치를 가리키며, CLUSTER 명령은 일회성으로 물리 정렬을 다시 해줄 뿐 이후 순서가 자동 유지되지는 않습니다. 반면 MySQL InnoDB는 기본키가 클러스터드 인덱스라 데이터 자체가 PK 순서로 리프에 저장되고, 보조 인덱스는 PK 값을 가리킵니다. 그래서 InnoDB는 PK 기반 조회·범위 스캔에 유리하지만 PK 변경·랜덤 PK 삽입 비용이 큰 차이가 있습니다."},
  {"id":"sc-db-17","cat":"DB","level":"기본","q":"LIKE '%abc'처럼 선행 와일드카드가 있는 검색이 인덱스를 못 타는 이유와 해결책은 무엇인가요?","a":"B-Tree 인덱스는 값이 앞에서부터 정렬되어 있어 접두어가 고정된 'abc%'는 범위로 좁힐 수 있지만, '%abc'처럼 앞이 와일드카드면 시작 지점을 특정할 수 없어 전체를 훑어야 하므로 인덱스가 무력화됩니다. 해결책으로는 PostgreSQL에서 pg_trgm 확장 기반 GIN/GiST 인덱스를 쓰거나, 전문검색(full-text)이 필요하면 GIN 기반 전문검색 인덱스를 사용합니다. 또는 컬럼을 뒤집어 저장한 표현식 인덱스를 만들어 접미어 검색을 접두어 검색으로 바꾸는 방법도 있습니다."},
  {"id":"sc-db-18","cat":"DB","level":"심화","q":"커버링 인덱스와 Index Only Scan이 무엇이며, Index Only Scan이 항상 보장되지 않는 이유는 무엇인가요?","a":"커버링 인덱스는 쿼리가 필요로 하는 컬럼을 인덱스가 모두 포함(PostgreSQL은 INCLUDE 컬럼 활용)해 heap을 읽지 않고 인덱스만으로 결과를 만드는 것이고, 이때 실행계획에 Index Only Scan이 나타납니다. 다만 PostgreSQL은 MVCC라 인덱스 엔트리만으로는 해당 튜플이 현재 트랜잭션에 보이는지 알 수 없어, visibility map에서 페이지가 all-visible로 표시된 경우에만 heap 접근을 생략할 수 있습니다. 그래서 VACUUM이 충분히 돌지 않아 visibility map이 갱신되지 않으면 heap을 다시 확인하게 되어 Index Only Scan이 보장되지 않습니다."},
  {"id":"sc-db-19","cat":"DB","level":"심화","q":"저카디널리티 컬럼 인덱스는 보통 무의미한데, 그럼에도 유효한 경우는 언제인가요?","a":"성별처럼 고유값 비율(선택성)이 낮은 컬럼은 인덱스를 타도 대부분의 행이 걸려 옵티마이저가 차라리 Seq Scan을 택하므로 단독 인덱스는 효과가 거의 없습니다. 그러나 전체 중 극소수만 해당하는 값을 자주 조회한다면 Partial Index가 유효합니다. 예를 들어 is_deleted=false나 status='PENDING'처럼 소수 행만 인덱싱하면 인덱스 크기가 작아지고 그 조건 조회는 매우 빨라집니다. 즉 값 분포가 한쪽으로 치우쳐 있고 그 희소한 쪽을 조회할 때 부분 인덱스로 의미를 가집니다."},
  {"id":"sc-db-20","cat":"DB","level":"심화","q":"트랜잭션 격리(Isolation)는 어떻게 구현되며, 격리수준을 높일수록 잃는 것은 무엇인가요?","a":"격리는 크게 락 기반과 MVCC 기반으로 구현됩니다. PostgreSQL은 MVCC로 읽기 일관성을 제공하고, READ COMMITTED는 매 문장마다 스냅샷을, REPEATABLE READ는 트랜잭션의 첫 쿼리 시점 스냅샷을 사용하며 SERIALIZABLE은 SSI로 직렬화 충돌을 감지합니다. 격리수준을 높이면 Dirty/Non-repeatable/Phantom Read 같은 이상현상이 줄어 정확성은 올라가지만, 동시 실행 가능성이 떨어져 동시성·처리량이 낮아지고 직렬화 실패로 인한 재시도 비용이 늘어납니다. 즉 일관성과 동시성을 맞바꾸는 트레이드오프입니다."},
  {"id":"sc-db-21","cat":"DB","level":"중급","q":"MVCC가 무엇이며, '읽기가 쓰기를 막지 않는다'는 말과 VACUUM이 필요한 이유를 설명해 주세요.","a":"MVCC는 행을 갱신할 때 기존 버전을 덮어쓰지 않고 xmin/xmax로 버전을 관리하며 새 버전을 만들어, 각 트랜잭션이 자기 스냅샷에 맞는 버전을 읽게 하는 방식입니다. 덕분에 읽는 쪽은 쓰는 쪽이 만든 새 버전을 기다릴 필요 없이 이전 버전을 읽을 수 있어 읽기가 쓰기를 막지 않고 그 반대도 마찬가지입니다. 다만 갱신·삭제로 더 이상 보이지 않는 dead tuple이 쌓이므로, VACUUM이 이를 정리해 공간을 회수하고 visibility map을 갱신해야 하며, 그렇지 않으면 테이블 bloat와 XID wraparound 위험이 생깁니다."},
  {"id":"sc-db-22","cat":"DB","level":"중급","q":"PostgreSQL의 기본 격리수준과 표준 REPEATABLE READ의 차이는 무엇인가요?","a":"PostgreSQL의 기본 격리수준은 READ COMMITTED입니다. 그리고 PostgreSQL의 REPEATABLE READ는 ANSI 표준이 허용하는 것보다 강해서, 표준에서는 RR이 Phantom Read를 허용하지만 PostgreSQL은 스냅샷 기반 MVCC로 구현되어 RR에서도 phantom까지 막아줍니다. 즉 표준 표만 외우면 PostgreSQL 동작을 잘못 예측할 수 있고, PostgreSQL의 RR은 사실상 스냅샷 격리(snapshot isolation)에 해당한다는 점을 알아야 합니다."},
  {"id":"sc-db-23","cat":"DB","level":"중급","q":"비관적 락과 낙관적 락은 언제 선택하며, JPA에서는 각각 어떻게 구현하나요?","a":"충돌이 드물면 낙관적 락을, 충돌이 잦으면 비관적 락을 택합니다. JPA 낙관적 락은 @Version으로 엔티티에 버전 컬럼을 두고, UPDATE 시 버전이 어긋나면 OptimisticLockException을 던져 충돌을 사후 감지하므로 보통 재시도 로직과 함께 씁니다. 비관적 락은 @Lock(LockModeType.PESSIMISTIC_READ/WRITE)로 걸며 내부적으로 SELECT ... FOR UPDATE(PESSIMISTIC_READ는 대체로 FOR SHARE)를 발행해 조회 시점에 행을 선점하는데, 정확한 SQL은 DB·Hibernate dialect에 따라 달라질 수 있습니다. 낙관적 락은 락 대기가 없어 처리량이 좋지만 충돌 시 재시도 비용이 들고, 비관적 락은 확실히 막지만 락 경합·데드락 위험이 있습니다."},
  {"id":"sc-db-24","cat":"DB","level":"기본","q":"데드락이 성립하는 네 가지 조건과 현실적으로 데드락을 줄이는 방법은 무엇인가요?","a":"데드락은 상호배제, 점유와 대기, 비선점, 순환대기 네 조건이 동시에 성립할 때 발생합니다. 현실적으로 가장 효과적인 예방은 순환대기를 깨는 것으로, 여러 자원을 잡을 때 항상 같은 순서로 락을 획득하도록 통일하는 것입니다. 그 밖에 락 타임아웃을 두어 무한 대기를 막고, 트랜잭션을 짧게 유지해 락 보유 시간을 줄입니다. PostgreSQL은 자동으로 데드락을 감지(detection)해 한쪽 트랜잭션을 abort시켜 해소하므로, 애플리케이션은 그 실패를 재시도로 처리하면 됩니다."},
  {"id":"sc-db-25","cat":"DB","level":"심화","q":"@Transactional의 REQUIRES_NEW와 NESTED의 차이를, 영속성 컨텍스트와 flush 시점 관점에서 설명해 주세요.","a":"REQUIRES_NEW는 기존 트랜잭션을 잠시 보류(suspend)하고 물리적으로 완전히 별도인 새 트랜잭션을 시작하므로, 안쪽이 독립적으로 커밋·롤백되고 바깥 롤백에 영향받지 않습니다. NESTED는 별도 트랜잭션이 아니라 같은 트랜잭션 내 savepoint를 만들어, 안쪽 실패 시 savepoint까지만 부분 롤백하고 바깥이 롤백되면 함께 롤백됩니다. 다만 NESTED는 JDBC savepoint에 의존하므로 JpaTransactionManager(JPA 단독) 환경에서는 savepoint를 지원하지 않아 NestedTransactionNotSupportedException이 날 수 있고, 주로 DataSourceTransactionManager(JDBC)에서 동작한다는 점에 유의해야 합니다. 영속성 컨텍스트는 트랜잭션 경계와 함께하므로 REQUIRES_NEW는 보류된 바깥과 분리된 새 트랜잭션에서 동작하며, 새 트랜잭션으로 진입하기 전 기존 변경이 flush될 수 있습니다. 또 같은 빈 내부의 self-invocation은 프록시를 거치지 않아 전파 설정이 무시되는 함정도 유의해야 합니다."},
  {"id":"sc-db-26","cat":"DB","level":"심화","q":"이른바 '따닥' 중복 결제를 DB 레벨에서 차단하는 방법을 설명해 주세요.","a":"첫째, 멱등키(idempotency key)를 결제 요청에 부여하고 그 컬럼에 UNIQUE 제약을 두면 같은 키의 두 번째 INSERT가 제약 위반으로 실패해 중복이 원천 차단됩니다. 둘째, 결제 대상 행에 비관적 락(SELECT ... FOR UPDATE, JPA의 @Lock(PESSIMISTIC_WRITE))을 걸어 동시 처리를 직렬화합니다. 셋째, 잔액·재고 차감처럼 상태가 걸린 경우 낙관적 락(@Version)으로 동시 갱신을 감지해 한쪽만 성공시킵니다. 실무에서는 UNIQUE 멱등키를 1차 방어선으로 두고 락을 보조로 조합하는 것이 견고합니다."},
  {"id":"sc-db-27","cat":"DB","level":"중급","q":"EXPLAIN과 EXPLAIN ANALYZE의 차이는 무엇이며, 실행계획에서 가장 먼저 봐야 할 신호는 무엇인가요?","a":"EXPLAIN은 옵티마이저의 추정 계획과 비용(cost)만 보여주고 실제로 쿼리를 실행하지는 않으며, EXPLAIN ANALYZE는 실제로 실행해 actual time과 실제 처리 행 수까지 보여줍니다. 가장 먼저 봐야 할 신호는 옵티마이저의 추정 rows와 실제 rows의 괴리입니다. 추정과 실제가 크게 어긋나면 통계가 낡았거나 부정확하다는 뜻이고, 이는 잘못된 조인 방식이나 스캔 선택으로 이어지므로 ANALYZE로 통계를 갱신해야 한다는 신호입니다. BUFFERS 옵션으로 실제 I/O 양도 함께 봅니다."},
  {"id":"sc-db-28","cat":"DB","level":"중급","q":"Nested Loop 조인과 Hash 조인은 각각 어떤 상황에서 유리한가요?","a":"Nested Loop는 한쪽 결과가 적고 다른 쪽에 조인 키 인덱스가 있어 매 행마다 인덱스로 빠르게 찾을 수 있을 때 유리합니다. 소량 데이터·인덱스 조회에 적합하지만 양쪽이 크면 반복 횟수가 폭증해 느립니다. Hash 조인은 한쪽으로 해시 테이블을 만들어 등호 조건으로 매칭하므로 대량 데이터를 등치 조인할 때 유리하지만, 해시 테이블 메모리가 필요하고 등호 조인에만 쓸 수 있습니다. 정렬된 대량 데이터끼리는 Sort-Merge 조인이 쓰입니다."},
  {"id":"sc-db-29","cat":"DB","level":"심화","q":"N+1 문제가 무엇이며, fetch join과 @EntityGraph, @BatchSize는 언제 무엇을 쓰는지 설명해 주세요.","a":"N+1은 목록을 한 번 조회한 뒤 각 엔티티의 지연로딩(LAZY) 연관을 루프에서 접근할 때마다 추가 쿼리가 N번 더 나가는 문제입니다. fetch join(JPQL join fetch)은 한 쿼리의 JOIN으로 연관을 즉시 로딩해 단건·소수 연관 조회에 유리하지만, 컬렉션 fetch join에 페이징을 붙이면 메모리 페이징 위험이 있고 컬렉션 두 개를 동시에 fetch join하면 MultipleBagFetchException이 납니다. @EntityGraph는 쿼리별로 어떤 연관을 즉시 로딩할지 선언적으로 지정하는 방식이고, @BatchSize나 hibernate.default_batch_fetch_size는 연관을 IN 쿼리로 묶어 N+1을 N/batch+1로 줄여 일대다 페이징에 적합합니다. 정리하면 단건 조회는 fetch join, 일대다 페이징은 batch fetch가 보통 유리합니다."},
  {"id":"sc-db-30","cat":"DB","level":"심화","q":"컬렉션을 fetch join하면서 페이징을 적용하면 위험한 이유는 무엇인가요?","a":"일대다 컬렉션을 fetch join하면 JOIN 결과가 자식 수만큼 부모 행을 중복시켜, DB의 LIMIT/OFFSET이 부모 단위가 아니라 조인된 곱 단위로 잘려 원하는 페이지가 깨집니다. 이를 막으려고 Hibernate는 페이징 조건을 DB에 내리지 못하고 전체를 메모리로 가져와 애플리케이션에서 페이징(메모리 페이징)하며, 'firstResult/maxResults specified with collection fetch; applying in memory' 경고를 남깁니다. 데이터가 크면 전체 적재로 메모리·성능 문제가 생기므로, 컬렉션 페이징은 fetch join 대신 @BatchSize 같은 batch fetch로 해결해야 합니다."},
  {"id":"sc-db-31","cat":"DB","level":"중급","q":"OFFSET 페이지네이션이 뒤로 갈수록 느려지는 이유와 keyset 방식의 트레이드오프를 설명해 주세요.","a":"OFFSET 방식은 건너뛸 행을 실제로 읽어서 버리기 때문에, OFFSET 10000이면 앞의 만 건을 모두 스캔한 뒤 버려 페이지가 뒤로 갈수록 비용이 선형으로 커집니다. keyset(cursor) 방식은 마지막으로 본 값을 기준으로 WHERE (created_at, id) < (?, ?) ORDER BY ... LIMIT n처럼 인덱스로 바로 그 지점부터 읽어 페이지 위치와 무관하게 일정하게 빠릅니다. 다만 keyset은 임의 페이지 번호로 점프하기 어렵고 정렬 키가 인덱스와 일치해야 하며 커서 관리가 필요하다는 단점이 있습니다. count를 생략해도 되면 Spring Data의 Slice로 다음 페이지 존재만 확인하는 방법도 있습니다."},
  {"id":"sc-db-32","cat":"DB","level":"심화","q":"인덱스가 있는데도 옵티마이저가 Seq Scan을 고르는 이유는 무엇인가요?","a":"옵티마이저는 비용 기반(CBO)으로 판단하므로, 조건에 걸리는 행이 테이블의 상당 비율이면 인덱스로 한 건씩 찾아 heap을 random I/O로 접근하는 것보다 순차로 한 번에 읽는 Seq Scan이 더 싸다고 판단합니다. 선택성이 낮은 조건, 작은 테이블, 또는 통계가 낡아 행 수를 잘못 추정한 경우에도 Seq Scan을 고를 수 있습니다. 통계가 원인일 때는 ANALYZE로 갱신하면 계획이 바뀌고, 정말 인덱스가 유리한데 못 타면 표현식 가공·형변환 같은 인덱스 무력화 요인을 함께 점검해야 합니다."},
  {"id":"sc-db-33","cat":"DB","level":"심화","q":"실행계획에서 추정 rows와 실제 rows의 괴리가 크면 원인은 무엇이며 어떻게 대처하나요?","a":"주된 원인은 통계가 낡거나 부족한 경우로, autovacuum/ANALYZE가 충분히 돌지 않아 옵티마이저가 데이터 분포를 잘못 추정하는 것입니다. 컬럼 간 상관관계나 편향된 분포, 복잡한 조건식도 추정을 어긋나게 합니다. 대처로는 ANALYZE로 통계를 갱신하고, default_statistics_target을 올려 히스토그램 정밀도를 높이거나, 다중 컬럼 상관에는 확장 통계(CREATE STATISTICS)를 만듭니다. 그래도 어긋나면 쿼리를 재작성해 옵티마이저가 추정하기 쉬운 형태로 바꾸는 것이 좋습니다."},
  {"id":"sc-db-34","cat":"DB","level":"기본","q":"JPA에서 count와 exists를 적절히 구분해 쓰는 이유는 무엇인가요?","a":"단지 데이터가 존재하는지만 확인하면 되는데 count(*)를 쓰면 조건에 맞는 모든 행을 세느라 불필요한 비용이 듭니다. 존재 여부는 첫 행을 찾으면 바로 끝나는 exists 쿼리가 훨씬 싸므로, '있는지'는 exists로 확인해야 합니다. 반대로 정확한 개수가 필요할 때만 count를 씁니다. 더불어 목록 조회 시 필요 컬럼만 가져오는 DTO 프로젝션을 쓰면 불필요한 컬럼 로딩과 영속성 컨텍스트 부담을 줄일 수 있습니다."},
  {"id":"sc-db-35","cat":"DB","level":"중급","q":"파티셔닝과 샤딩의 차이는 무엇이며, 샤드 키를 잘못 고르면 어떤 결과가 생기나요?","a":"파티셔닝은 한 DB 서버 안에서 큰 테이블을 range/list/hash 기준으로 여러 파티션으로 나누는 것이고, 샤딩은 데이터를 여러 서버에 나눠 저장해 수평 확장하는 것입니다. 즉 파티셔닝은 서버 내, 샤딩은 서버 간 분할입니다. 샤드 키를 잘못 고르면 특정 샤드에 트래픽·데이터가 몰리는 핫스팟이 생기고, 분포가 바뀌면 데이터를 재분배하는 rebalancing 비용이 큽니다. 또한 여러 샤드에 걸친 크로스 샤드 조인·트랜잭션이 어려워지므로, 접근이 고르게 분산되고 조인이 한 샤드 안에서 끝나도록 키를 정해야 합니다."},
  {"id":"sc-db-36","cat":"DB","level":"중급","q":"read replica를 쓸 때 생기는 정합성 문제는 무엇이며 어떻게 해결하나요?","a":"비동기 복제에서는 primary의 변경이 replica에 반영되기까지 복제 지연(replication lag)이 있어, 방금 쓴 데이터를 곧바로 replica에서 읽으면 옛 값이 보이는 read-after-write 불일치가 생깁니다. 해결책으로는 방금 쓴 사용자의 직후 읽기 같은 중요한 읽기를 primary로 보내거나, 동기 복제로 일관성을 강제하거나(처리량 희생), replica의 적용 위치(LSN)가 쓴 시점을 따라잡았는지 확인한 뒤 읽는 방식이 있습니다. Spring에서는 AbstractRoutingDataSource와 @Transactional(readOnly=true)로 읽기를 replica로 라우팅하되 일관성이 중요한 읽기는 예외적으로 primary로 분기합니다."},
  {"id":"sc-db-37","cat":"DB","level":"심화","q":"CAP 정리에서 'CA 시스템'이라는 표현이 부정확한 이유와, 단일 노드 PostgreSQL은 어떻게 분류해야 하나요?","a":"CAP는 네트워크 분할(P)이 발생한 상황에서 일관성(C)과 가용성(A) 중 하나를 포기해야 한다는 정리입니다. 분산 시스템에서 네트워크 분할은 선택 사항이 아니라 언젠가 반드시 일어나는 현실이므로, P를 버린 'CA 시스템'은 분산 환경에서 성립하지 않는 표현입니다. 단일 노드 PostgreSQL은 애초에 노드가 하나라 분할 개념 자체가 없으니 CAP의 분류 대상이 아니며, CP/AP로 라벨링하는 것 자체가 부적절합니다. 더 현실적인 모델로는 분할이 없을 때의 지연(Latency)과 일관성 트레이드오프까지 다루는 PACELC가 있습니다."},
  {"id":"sc-db-38","cat":"DB","level":"중급","q":"별도의 NoSQL을 도입하지 않고 PostgreSQL의 jsonb만으로 충분한 경우는 언제인가요?","a":"스키마가 유동적이거나 문서 형태의 반정형 데이터를 다뤄야 하지만, 기존 관계형 데이터와 함께 트랜잭션·조인·강한 정합성도 필요한 경우 jsonb가 좋은 선택입니다. PostgreSQL은 jsonb 컬럼에 GIN 인덱스를 걸어 @>나 ->> 같은 연산으로 문서 내부를 효율적으로 조회할 수 있어, NoSQL의 유연성 요구를 상당 부분 흡수합니다. 별도 저장소를 운영·동기화하는 비용 없이 한 DB 안에서 관계형과 문서형을 함께 쓸 수 있을 때 jsonb로 충분합니다. 초대용량 분산 확장이나 특정 NoSQL 고유 모델이 핵심일 때만 전용 NoSQL을 고려합니다."},
  {"id":"sc-db-39","cat":"DB","level":"중급","q":"커넥션 풀 크기를 무작정 키우면 오히려 나빠지는 이유와, HikariCP와 PgBouncer의 역할 차이는 무엇인가요?","a":"DB가 동시에 효율적으로 처리할 수 있는 연결 수는 CPU 코어와 디스크 같은 자원에 의해 제한되므로, 풀을 그 한계 이상으로 키우면 컨텍스트 스위칭과 락 경합이 심해져 오히려 처리량이 떨어지고 응답이 느려집니다. 그래서 풀 크기는 자원 기준의 적정값으로 잡아야 합니다. HikariCP는 애플리케이션 측 커넥션 풀로 Spring Boot의 기본이며 maximumPoolSize·connectionTimeout 등으로 앱당 연결을 관리합니다. PgBouncer는 DB 앞단에 두는 서버 측 풀러로, 여러 앱 인스턴스의 연결을 모아 실제 DB 연결 수를 줄여줍니다. 둘은 계층이 달라, 앱이 많아 DB 연결 한계를 넘을 때 HikariCP 위에 PgBouncer를 추가로 둡니다."},
  {"id":"sc-db-40","cat":"DB","level":"중급","q":"PostgreSQL에서 VACUUM을 하지 않으면 어떤 문제가 생기나요?","a":"PostgreSQL은 MVCC라 UPDATE/DELETE 시 옛 버전이 dead tuple로 남는데, VACUUM이 이를 정리하지 않으면 테이블과 인덱스가 부풀어 오르는 bloat가 생겨 디스크를 낭비하고 스캔 성능이 떨어집니다. 또 visibility map이 갱신되지 않아 Index Only Scan이 제대로 동작하지 않습니다. 가장 치명적인 것은 트랜잭션 ID가 약 21억 범위를 한 바퀴 도는 XID wraparound로, VACUUM이 오래된 XID를 동결(freeze)하지 못하면 데이터 손실을 막기 위해 DB가 쓰기를 강제로 중단시킬 수 있습니다. 그래서 autovacuum이 적절히 도는지 모니터링이 중요합니다."},
  {"id":"sc-db-41","cat":"DB","level":"심화","q":"캐시 정합성과 캐시 스탬피드(thundering herd)를 어떻게 차단하나요?","a":"look-aside 캐시에서는 DB가 갱신될 때 캐시가 옛값을 들고 있어 정합성이 깨질 수 있으므로, 쓰기 시 캐시를 무효화하거나 write-through로 캐시와 DB를 함께 갱신하고, 완벽한 동기화가 어렵다면 적절한 TTL로 오차를 제한합니다. 캐시 스탬피드는 인기 키가 동시에 만료되어 다수 요청이 한꺼번에 DB로 몰리는 현상으로, 캐시를 다시 채우는 동안 락이나 단일 비행(single-flight)으로 한 요청만 DB를 치게 하고 나머지는 대기시킵니다. 또한 만료 시각에 무작위 지터를 주어 동시 만료를 분산하거나, 만료 직전 미리 비동기로 재계산하는 방식으로 완화합니다."},
  {"id":"sc-db-42","cat":"DB","level":"중급","q":"SQLD 기준으로 NATURAL JOIN, USING, ON의 차이와, USING/ON에서 공통 컬럼이 결과에 몇 번 나오는지 설명해 주세요.","a":"NATURAL JOIN은 양쪽의 동일명 컬럼을 자동으로 찾아 조인하며, 공통 컬럼은 한 번만 출력되고 조인 컬럼에 테이블 한정자를 붙일 수 없으며 ON/USING과 같은 join 절에 병용할 수 없습니다. JOIN ... USING(col)은 명시한 동일명 컬럼으로 조인하고 그 공통 컬럼을 결과에 한 번만 출력합니다. JOIN ... ON은 조건을 직접 명시하는 방식으로 양쪽 컬럼이 각각 결과에 나와 SELECT *로 조회하면 공통 컬럼이 두 번 출력됩니다. PostgreSQL도 ANSI 표준 조인은 동일하게 동작하지만, Oracle 구식 외부조인 표기인 (+)는 지원하지 않습니다."},
  {"id":"sc-db-43","cat":"DB","level":"기본","q":"UNION과 UNION ALL의 차이(정렬·중복·성능)와, MINUS와 PostgreSQL의 EXCEPT 관계를 설명해 주세요.","a":"UNION은 두 결과를 합치면서 중복을 제거하는데, 이를 위해 정렬 또는 해싱 작업이 들어가 비용이 추가됩니다. UNION ALL은 중복을 제거하지 않고 그대로 이어 붙여 별도 정렬이 없으므로 더 빠르며, 중복이 없음을 안다면 UNION ALL이 권장됩니다. 차집합은 Oracle에서 MINUS로 쓰지만 MINUS는 Oracle 전용이고, PostgreSQL을 비롯한 ANSI 표준은 동일한 의미의 EXCEPT를 씁니다(둘 다 ALL을 붙이지 않으면 중복을 제거함). 집합연산은 컬럼 수·타입이 호환되어야 하고 ORDER BY는 맨 마지막에 한 번만 붙입니다."},
  {"id":"sc-db-44","cat":"DB","level":"심화","q":"Oracle 계층형 질의에서 CONNECT BY PRIOR의 PRIOR 위치가 부모-자식 방향을 어떻게 정하며, PostgreSQL의 대응 문법은 무엇인가요?","a":"CONNECT BY PRIOR는 PRIOR가 붙은 컬럼이 '이전(상위) 행'의 값을 가리켜 연결 방향을 정합니다. 예를 들어 CONNECT BY PRIOR id = parent_id는 상위 행의 id가 현재 행의 parent_id와 같다는 의미라 루트에서 자식으로 내려가는 top-down 전개이고, PRIOR를 반대쪽에 붙이면 자식에서 부모로 거슬러 올라가는 방향이 됩니다. START WITH로 루트 조건을, 의사컬럼 LEVEL로 깊이를 표현합니다. 이 CONNECT BY 계열은 Oracle 전용이라, PostgreSQL에서는 WITH RECURSIVE 재귀 CTE로 같은 결과를 만들며(깊이는 LEVEL 대신 depth+1처럼 직접 누적), 문법이 완전히 다릅니다."},
  {"id":"sc-db-45","cat":"DB","level":"기본","q":"RANK, DENSE_RANK, ROW_NUMBER의 출력 차이를 동순위가 있을 때를 예로 설명해 주세요.","a":"세 함수 모두 윈도우(분석) 함수로 순위를 매기지만 동순위 처리가 다릅니다. RANK는 동순위에 같은 등수를 주고 다음 순위를 건너뛰어 1,1,3처럼 매깁니다. DENSE_RANK는 동순위에 같은 등수를 주되 건너뛰지 않아 1,1,2가 됩니다. ROW_NUMBER는 동순위를 인정하지 않고 무조건 고유한 일련번호를 부여해 1,2,3이 됩니다. 정확한 Top-N이나 페이징처럼 유일한 번호가 필요하면 ROW_NUMBER를, 공동 순위를 표현하려면 RANK/DENSE_RANK를 씁니다."},
  {"id":"sc-db-46","cat":"DB","level":"중급","q":"ROLLUP과 CUBE가 만드는 소계 집합의 차이와, GROUPING() 함수의 반환값(0/1) 용도를 설명해 주세요.","a":"ROLLUP(a,b)는 계층적 소계를 만들어 (a,b) 조합별 집계에 더해 a별 소계와 전체 총합을 생성합니다. CUBE(a,b)는 가능한 모든 조합의 소계를 만들어 (a,b), a별, b별, 전체 총합까지 모두 포함합니다. 즉 ROLLUP은 지정 순서의 부분집합만, CUBE는 모든 부분집합을 생성합니다. GROUPING()은 해당 행이 그 컬럼에 대해 소계·총합으로 집계된 행이면 1을, 일반 그룹 행이면 0을 반환해 소계행을 식별하고 라벨링하는 데 씁니다. PostgreSQL도 ROLLUP/CUBE/GROUPING SETS를 동일하게 지원합니다."},
  {"id":"sc-db-47","cat":"DB","level":"심화","q":"Oracle에서 WHERE ROWNUM > 1이 항상 빈 결과인 이유와 올바른 Top-N 작성법, 그리고 PostgreSQL의 대응 문법은 무엇인가요?","a":"ROWNUM은 WHERE 조건을 통과한 행에 1부터 순차로 부여되는데, 첫 행이 ROWNUM=1을 받으려면 먼저 통과해야 합니다. 그런데 ROWNUM > 1 조건은 첫 행을 탈락시켜 영영 1번이 확정되지 않으므로 어떤 행도 통과하지 못해 항상 빈 결과가 됩니다. 또 ROWNUM은 정렬·집계 이전에 부여되므로 WHERE ROWNUM <= N을 정렬 전에 쓰면 엉뚱한 행이 잘립니다. 올바른 Top-N은 인라인 뷰에서 ORDER BY로 정렬한 뒤 바깥에서 ROWNUM을 걸거나 ROW_NUMBER() OVER(ORDER BY ...)를 쓰는 것입니다. ROWNUM은 Oracle 전용이며 PostgreSQL은 LIMIT n [OFFSET m] 또는 ANSI 표준 FETCH FIRST n ROWS ONLY를 씁니다(Oracle도 12c부터 FETCH FIRST를 지원합니다)."},
  {"id":"sc-db-48","cat":"DB","level":"심화","q":"PIVOT이 Oracle 전용인 이유와 PostgreSQL에서의 대체 방법을 설명해 주세요.","a":"PIVOT은 행을 열로 전환하며 집계를 동반하는 구문으로 Oracle 11g 이상에서 제공하는 전용 문법이라, PostgreSQL에는 네이티브 PIVOT 구문이 없습니다. PostgreSQL에서는 조건부 집계, 즉 SUM(CASE WHEN 조건 THEN 값 END)을 컬럼별로 나열하거나 집계 함수의 FILTER 절을 써서 같은 효과를 냅니다. 동적으로 열을 만들어야 하면 tablefunc 확장의 crosstab 함수를 사용합니다. 반대로 열을 행으로 푸는 UNPIVOT도 Oracle 전용이며, PostgreSQL에서는 UNION ALL이나 unnest 등으로 대체합니다."},
  {"id":"sc-db-49","cat":"DB","level":"심화","q":"TRUNCATE가 Oracle에서 롤백되지 않는 이유와 PostgreSQL에서의 차이, 그리고 MERGE가 처리하는 일을 설명해 주세요.","a":"Oracle에서 TRUNCATE는 DDL이고, Oracle은 DDL 실행 시 앞뒤로 암묵적 COMMIT을 수행하기 때문에 TRUNCATE 전후의 트랜잭션이 확정되어 롤백할 수 없습니다. SQLD는 이 Oracle 기준입니다. 반면 PostgreSQL은 DDL도 트랜잭션 안에서 동작해 BEGIN 후 TRUNCATE를 하고 ROLLBACK하면 데이터가 복구되며, 대부분의 DDL을 롤백할 수 있습니다(CREATE DATABASE 등 일부 예외). MERGE는 UPSERT 구문으로, USING ... ON 조건으로 대상을 매칭해 WHEN MATCHED면 UPDATE, WHEN NOT MATCHED면 INSERT를 한 번에 처리합니다. PostgreSQL은 15부터 MERGE를 지원하며, 그 이전·대안으로는 동시성 보장 방식이 다른 INSERT ... ON CONFLICT를 씁니다."},
  {"id":"sc-algo-1","cat":"ALGO","level":"기본","q":"바깥 루프가 n번 도는 안에서 매번 이분탐색을 호출하면 전체 시간복잡도는 어떻게 되나요?","a":"이분탐색 한 번이 O(log n)이고 그걸 n번 반복하므로 전체는 O(n log n)입니다. 곱셈으로 합성되는 구조라 바깥 반복 횟수 × 안쪽 호출 비용으로 계산하면 됩니다. 정렬된 데이터에서 각 원소마다 위치를 찾는 전형적인 패턴입니다."},
  {"id":"sc-algo-2","cat":"ALGO","level":"기본","q":"n=10^5 입력에서 O(n²) 풀이가 시간 내에 통과할 수 있을까요? 근거와 함께 설명해 주세요.","a":"통과하지 못합니다. (10^5)²=10^10 연산인데, Java 기준 1초에 약 10^8 연산이 어림이라 약 100초가 걸려 예산을 두 자릿수 배 초과합니다. n=10^5면 O(n log n) 정도까지가 안전선이고, O(n²)는 n이 5000 안팎일 때만 허용된다고 보면 됩니다. 그래서 문제를 풀기 전에 입력 한계로 목표 복잡도부터 역산하는 게 중요합니다."},
  {"id":"sc-algo-3","cat":"ALGO","level":"중급","q":"Java의 ArrayList.add가 상각(amortized) O(1)이라고 하는 이유를 설명해 주세요. 단일 add의 최악 복잡도는 어떻게 되나요?","a":"용량이 차면 1.5배(oldCapacity + oldCapacity>>1)로 재할당하면서 전체 복사 O(n)이 발생하지만, 이 비용이 그 전까지의 여러 add에 분산되어 평균하면 add 한 번당 O(1)이 됩니다. 즉 가끔의 O(n) 재할당 비용을 다수의 add가 나눠 갚는 셈입니다. 다만 단일 add의 최악은 재할당이 일어나는 그 순간이라 여전히 O(n)이라는 점을 구분해야 합니다."},
  {"id":"sc-algo-4","cat":"ALGO","level":"기본","q":"Java에서 스택, 큐, 덱을 하나의 자료구조로 통일해서 쓴다면 무엇을 선택하고 그 이유는 무엇인가요?","a":"ArrayDeque를 씁니다. 양끝 삽입·삭제가 O(1)이라 스택은 push/pop, 큐는 offer/poll, 덱은 양끝 연산으로 모두 커버됩니다. 구식 Stack 클래스는 Vector 기반에 동기화 오버헤드가 있고, LinkedList는 노드마다 객체 할당과 캐시 비친화성이 있어서 ArrayDeque가 더 빠릅니다. 그래서 코테에서는 셋 다 ArrayDeque로 통일하는 게 관용구입니다."},
  {"id":"sc-algo-5","cat":"ALGO","level":"중급","q":"해시 테이블의 평균 O(1) 조회가 최악 O(n)으로 무너지는 상황은 언제이고, Java 8 이상에서는 이를 어떻게 완화하나요?","a":"한 버킷에 충돌이 집중되면(예: 같은 해시로 몰리는 키들) 그 버킷이 사실상 선형 리스트가 되어 탐색이 O(n)으로 떨어집니다. Java 8 이상에서는 한 버킷의 길이가 8 이상이면서 테이블 용량이 64 이상일 때 그 버킷을 레드블랙 트리로 변환(treeify)해 해당 버킷 탐색을 O(log n)으로 보장합니다. 평소에는 체이닝과 load factor 기반 리해싱으로 평균 O(1)을 유지합니다."},
  {"id":"sc-algo-6","cat":"ALGO","level":"중급","q":"퀵 정렬과 머지 정렬을 안정성, 추가 메모리, 최악 시간복잡도 세 측면에서 비교해 주세요.","a":"퀵 정렬은 불안정 정렬이고 in-place라 재귀 스택만 평균 O(log n) 쓰지만 피벗이 치우치면 최악 O(n²)입니다. 머지 정렬은 안정 정렬이지만 병합용 추가 배열 O(n)이 필요하고 대신 항상 O(n log n)을 보장합니다. 그래서 최악을 막아야 하거나 안정성이 필요하면 머지, 메모리가 빠듯하고 평균 성능이면 퀵을 고릅니다."},
  {"id":"sc-algo-7","cat":"ALGO","level":"기본","q":"Java의 Collections.sort나 Arrays.sort(객체 배열)는 안정 정렬인가요? 다중 기준 정렬은 어떻게 구현하나요?","a":"예, 객체(참조형) 정렬에는 안정 정렬인 TimSort를 씁니다. 참고로 기본형 배열(int[] 등)은 듀얼피벗 퀵정렬이라 불안정합니다. 다중 기준 정렬은 Comparator.comparing(...).thenComparing(...)으로 1차·2차 키를 이어 붙이고, 내림차순이 필요하면 reversed()를 붙입니다."},
  {"id":"sc-algo-8","cat":"ALGO","level":"중급","q":"'다음 큰 수(Next Greater Element)'를 전체 O(n)에 푸는 자료구조는 무엇이고, 스택에는 무엇을 넣나요?","a":"단조 스택(Monotonic Stack)을 씁니다. 보통 값이 아니라 인덱스를 넣고, 스택이 단조 감소를 유지하도록 새 원소가 더 크면 스택을 pop하면서 'pop되는 원소의 다음 큰 수=현재 원소'로 확정합니다. 각 원소가 스택에 정확히 한 번 push되고 한 번 pop되므로 전체가 O(n)이 됩니다."},
  {"id":"sc-algo-9","cat":"ALGO","level":"기본","q":"슬라이딩 윈도우로 풀 수 있다는 신호는 어떤 문제 형태인가요? 어떤 경우에 단순 슬라이딩 윈도우가 깨지나요?","a":"연속 구간(부분배열)을 다루면서, 윈도우를 늘리면 조건이 한 방향으로 강해지고 줄이면 약해지는 단조적 성질이 있을 때가 신호입니다. 예를 들어 '합 ≥ S인 최소 길이 구간' 같은 문제가 전형적입니다. 다만 값에 음수가 섞이면 윈도우를 늘려도 합이 단조 증가하지 않아 늘리고 줄이는 불변식이 깨지므로, 양수 배열 가정이 필요합니다."},
  {"id":"sc-algo-10","cat":"ALGO","level":"기본","q":"해시를 써서 문제를 풀 때의 시간·공간 트레이드오프를 한 문장으로 설명해 주세요.","a":"추가 메모리 O(n)을 써서 조회·삽입을 평균 O(1)로 사는 것입니다. 즉 공간을 더 쓰는 대신 이중 루프 O(n²)로 찾던 존재 여부·빈도·매핑을 선형 시간으로 끝낼 수 있습니다. 정렬이나 범위 조회가 필요해지면 그때는 TreeMap 같은 O(log n) 구조로 넘어가는 게 신호입니다."},
  {"id":"sc-algo-11","cat":"ALGO","level":"심화","q":"파라메트릭 서치와 일반 이분탐색의 차이를 설명하고, 파라메트릭 서치의 결정함수가 만족해야 할 성질은 무엇인지 말해 주세요.","a":"일반 이분탐색은 '정렬된 배열'에서 값을 찾지만, 파라메트릭 서치는 '답 후보 공간' 자체를 이분탐색합니다. 즉 '최댓값을 최대로' 같은 최적화 문제를 'X가 가능한가? yes/no' 결정문제로 바꿔 답을 직접 탐색합니다. 핵심 조건은 결정함수가 답 기준 단조성을 가져야 한다는 것, 즉 어떤 임계값을 경계로 yes↔no가 딱 한 번만 바뀌어야 이분탐색이 성립합니다(예: Koko Eating Bananas류)."},
  {"id":"sc-algo-12","cat":"ALGO","level":"기본","q":"Java의 PriorityQueue로 최대힙을 만드는 두 가지 방법은 무엇이고, 비교자를 쓸 때 주의할 점은 무엇인가요?","a":"PriorityQueue는 기본이 최소힙이라, Comparator.reverseOrder()를 넘기거나 (a,b)->b-a 같은 비교자를 주면 최대힙이 됩니다. 다만 b-a 방식은 값이 아주 크거나 작을 때 int 오버플로로 부호가 뒤집힐 위험이 있어, 값 범위가 크면 Integer.compare(b,a)를 쓰는 게 안전합니다. offer/poll이 O(log n), peek이 O(1)입니다."},
  {"id":"sc-algo-13","cat":"ALGO","level":"기본","q":"완전탐색(브루트포스)이 허용되는 입력 크기 n은 대략 얼마인가요? 경우의 수 종류별로 말해 주세요.","a":"역산표 기준으로, 순열을 모두 만드는 n!이면 n이 10 안팎까지, 부분집합을 모두 보는 2^n이면 n이 20~25 정도까지가 한계입니다. Java 1초에 약 10^8 연산이라 2^20≈10^6, 10!≈3.6×10^6 수준은 통과하지만 그 이상은 폭발합니다. '모든 조합/순열을 본다'가 신호이고, 입력이 이 범위 안일 때 완전탐색을 선택합니다."},
  {"id":"sc-algo-14","cat":"ALGO","level":"기본","q":"백트래킹에서 '가지치기(pruning)'가 없으면 어떤 문제가 생기나요?","a":"조건을 위반한 부분해까지 끝까지 탐색하게 되어 탐색 공간이 지수적으로 폭발하고 시간초과가 납니다. 백트래킹의 핵심은 부분해를 만들다 조건을 어기면 더 내려가지 않고 즉시 되돌아가(가지치기) 불필요한 분기를 잘라내는 것입니다. N-Queen처럼 유망하지 않은 가지를 빨리 버려야 실용적인 시간에 풀립니다."},
  {"id":"sc-algo-15","cat":"ALGO","level":"중급","q":"lower bound와 upper bound의 차이는 무엇이고, Java 표준 binarySearch를 경계 탐색에 바로 쓸 수 없는 이유는 무엇인가요?","a":"lower bound는 찾는 값이 중복으로 있을 때 그 첫 위치(같은 값 앞쪽), upper bound는 같은 값 바로 뒤 위치를 반환해 각각 첫/마지막 위치 탐색에 씁니다. Java의 Arrays.binarySearch나 Collections.binarySearch는 값이 중복일 때 일치하는 여러 위치 중 어느 것을 반환할지 보장하지 않습니다. 그래서 정확한 경계(첫/마지막 위치)를 찾으려면 <= vs < 경계 조건을 직접 다룬 lower/upper bound를 구현해야 합니다."},
  {"id":"sc-algo-16","cat":"ALGO","level":"기본","q":"간선 가중치가 모두 1인 그래프의 최단거리에서 DFS 대신 BFS를 쓰는 이유는 무엇인가요?","a":"BFS는 시작점에서 거리 오름차순으로 노드를 방문하기 때문에 어떤 노드에 처음 도달한 순간이 곧 최단거리임이 보장됩니다. 반면 일반 DFS는 깊이 우선으로 들어가서 먼저 도달한 경로가 최단이라는 보장이 없습니다. 그래서 가중치가 모두 같은(또는 1인) 경우의 최단거리는 ArrayDeque 큐로 BFS를 돌립니다."},
  {"id":"sc-algo-17","cat":"ALGO","level":"중급","q":"BFS에서 방문 표시를 '큐에 넣을 때'와 '큐에서 꺼낼 때' 중 언제 해야 중복이 없나요?","a":"큐에 넣는 시점(enqueue)에 방문 표시를 해야 합니다. 꺼낼 때 표시하면 같은 노드가 여러 이웃을 통해 큐에 중복으로 들어가, 메모리가 늘고 같은 노드를 여러 번 처리하게 됩니다. enqueue 시점에 표시하면 각 노드가 큐에 정확히 한 번만 들어가 O(V+E)가 유지됩니다."},
  {"id":"sc-algo-18","cat":"ALGO","level":"중급","q":"유니온-파인드에서 경로 압축(path compression)과 union by rank는 각각 무엇을 최적화하나요?","a":"경로 압축은 find를 수행할 때 거쳐 간 노드들을 루트에 직접 연결해 다음 find의 경로를 짧게 만듭니다. union by rank(또는 size)는 더 낮은 트리를 높은 트리 밑에 붙여 트리 높이가 커지는 것을 억제합니다. 이 둘을 함께 쓰면 find/union이 상각 역아커만 α(n), 사실상 거의 상수 시간이 됩니다."},
  {"id":"sc-algo-19","cat":"ALGO","level":"심화","q":"0-1 BFS가 일반 다익스트라보다 빠른 조건은 무엇이고 어떻게 구현하나요?","a":"간선 가중치가 0과 1 두 종류뿐일 때 0-1 BFS를 쓸 수 있습니다. ArrayDeque(덱)를 써서 가중치 0인 간선으로 가는 노드는 addFirst로 앞에, 1인 간선은 addLast로 뒤에 넣으면 우선순위 큐 없이도 거리 오름차순이 유지됩니다. 그러면 힙의 log 비용이 사라져 다익스트라의 O((V+E)log V) 대신 O(V+E)에 풀립니다."},
  {"id":"sc-algo-20","cat":"ALGO","level":"중급","q":"Java 재귀 DFS가 깊은 그래프에서 StackOverflowError로 터질 때 대처 방법 두 가지를 말해 주세요.","a":"첫째, JVM 실행 옵션 -Xss로 스레드 스택 크기를 키워 재귀 깊이 한계를 늘리는 방법이 있습니다. 둘째, 재귀를 명시적 스택(ArrayDeque)을 쓰는 반복 DFS로 바꿔 JVM 호출 스택에 의존하지 않게 하는 방법이 있습니다. 입력이 일렬로 깊어질 수 있는 그래프에서는 후자가 더 안전합니다."},
  {"id":"sc-algo-21","cat":"ALGO","level":"심화","q":"다익스트라가 음수 간선이 있는 그래프에서 틀리는 이유는 무엇이고, 그때의 대안은 무엇인가요?","a":"다익스트라는 한 번 최단거리를 확정한 노드는 다시 갱신하지 않는다는 그리디 가정에 기반합니다. 음수 간선이 있으면 이미 확정한 노드의 거리가 나중에 음수 간선을 거쳐 더 줄어들 수 있어 이 가정이 깨집니다. 그래서 음수 간선이 있으면 모든 간선을 V-1회 완화하는 벨만포드(또는 SPFA)를 쓰고, 이 방법은 음수 사이클 탐지도 가능합니다."},
  {"id":"sc-algo-22","cat":"ALGO","level":"심화","q":"플로이드워셜에서 경유지 k 루프가 가장 바깥에 와야 하는 이유는 무엇인가요?","a":"플로이드워셜은 'k번 노드까지를 경유지로 허용했을 때의 모든 쌍 최단거리'를 단계적으로 확장하는 알고리즘입니다. k 루프가 가장 바깥에 있어야 각 k에 대해 모든 (i,j) 쌍을 갱신 완료한 뒤 다음 경유지 k+1로 넘어가, 점화식 dist[i][j]=min(dist[i][j], dist[i][k]+dist[k][j])이 올바르게 성립합니다. i나 j를 바깥에 두면 경유지 집합이 일관되게 확장되지 않아 틀린 답이 나옵니다."},
  {"id":"sc-algo-23","cat":"ALGO","level":"중급","q":"밀집 그래프의 MST를 구할 때 크루스칼과 프림 중 무엇을 고르고 그 이유는 무엇인가요?","a":"밀집 그래프(간선이 V²에 가까움)에서는 프림이 유리합니다. 크루스칼은 간선을 전부 정렬하는 O(E log E)가 드는데, 밀집이면 E가 V²급이라 정렬 비용이 큽니다. 반면 프림을 인접행렬 기반으로 구현하면 힙 없이 O(V²)로 돌릴 수 있어 더 빠를 수 있습니다. 희소 그래프라면 반대로 크루스칼(간선 정렬 + 유니온-파인드)이 유리합니다."},
  {"id":"sc-algo-24","cat":"ALGO","level":"중급","q":"위상정렬이 불가능한 그래프를 어떻게 감지하나요?","a":"위상정렬은 DAG(사이클 없는 방향 그래프)에서만 가능하므로, 사이클이 있으면 불가능합니다. Kahn 알고리즘으로 진입차수 0인 노드부터 차례로 빼내는 경우, 사이클에 속한 노드는 진입차수가 끝내 0이 되지 못해 결과에 포함되지 못합니다. 따라서 결과에 담긴 노드 수가 전체 노드 수보다 적으면 사이클이 있다고 판정합니다."},
  {"id":"sc-algo-25","cat":"ALGO","level":"중급","q":"그리디가 최적해를 보장하지 못하는 예를 하나 들고, 그때는 무엇으로 푸나요?","a":"임의의 동전 체계에서 거스름돈 최소 개수가 대표적입니다. 예를 들어 1, 3, 4원 동전으로 6원을 만들 때 큰 동전부터 그리디로 고르면 4+1+1로 3개지만, 최적은 3+3으로 2개라 그리디가 틀립니다. 이렇게 탐욕 선택 속성이 성립하지 않는 경우는 모든 경우를 고려하는 DP로 풀어야 합니다. 그리디는 '탐욕 선택 속성 + 최적 부분 구조'가 증명될 때만 안전합니다."},
  {"id":"sc-algo-26","cat":"ALGO","level":"기본","q":"어떤 문제를 보고 '이건 DP다'라고 판단하는 신호 두 가지는 무엇인가요?","a":"겹치는 부분 문제(overlapping subproblems)와 최적 부분 구조(optimal substructure) 두 가지입니다. 같은 작은 문제를 여러 번 반복해서 풀게 되고(메모이제이션으로 재사용 가능), 큰 문제의 최적해가 부분 문제들의 최적해로 구성되면 DP가 적합합니다. 완전탐색이 지수 시간일 때 메모이제이션으로 상태 수 × 전이 비용의 다항 시간으로 떨어뜨리는 게 핵심입니다."},
  {"id":"sc-algo-27","cat":"ALGO","level":"심화","q":"0/1 배낭을 1차원 배열로 압축할 때 무게(용량)를 역순으로 순회해야 하는 이유는 무엇인가요?","a":"1차원으로 압축하면 dp[w]가 이전 물건까지의 결과와 현재 물건을 쓴 결과를 같은 배열에서 갱신합니다. 용량을 역순(큰 쪽부터)으로 돌면 dp[w]를 갱신할 때 참조하는 dp[w-weight]가 아직 이번 물건으로 갱신되지 않은 '이전 물건까지의 값'이라, 같은 물건을 두 번 쓰는 일이 없습니다. 정순으로 돌면 이미 이번 물건을 쓴 값을 다시 참조해 중복 사용이 생기는데, 그게 바로 무한(완전) 배낭의 순회 방향입니다."},
  {"id":"sc-algo-28","cat":"ALGO","level":"심화","q":"LIS(최장 증가 부분수열)를 O(n log n)으로 푸는 핵심 아이디어는 무엇인가요?","a":"'길이 k인 증가 부분수열이 가질 수 있는 최소 꼬리값'을 모아 둔 배열을 유지하면서, 각 원소마다 이분탐색으로 들어갈 위치를 찾아 갱신합니다. 새 값이 배열 끝보다 크면 길이를 늘리고, 아니면 lower bound 위치의 값을 교체합니다. 이 배열의 길이가 곧 LIS 길이이며(배열 내용 자체는 실제 LIS가 아님에 주의), 각 원소당 이분탐색 O(log n)이라 전체 O(n log n)이 됩니다."},
  {"id":"sc-algo-29","cat":"ALGO","level":"중급","q":"DP를 Top-down과 Bottom-up 중 각각 언제 고르나요?","a":"Top-down(메모이제이션 재귀)은 필요한 상태만 방문하거나 전이가 복잡해 반복문으로 표현하기 까다로울 때 직관적이라 유리합니다. Bottom-up은 모든 상태를 규칙적으로 채우고 재귀 깊이가 깊을 때, 스택 안전하고 호출 오버헤드가 없어 상수적으로 빠른 경향이 있습니다. 깊은 재귀가 StackOverflowError를 낼 위험이 있으면 Bottom-up으로 바꾸는 게 안전합니다."},
  {"id":"sc-algo-30","cat":"ALGO","level":"중급","q":"그리디로 풀릴 것 같지만 실제로는 DP가 필요한 경우의 예를 들어 주세요.","a":"임의 동전 체계의 거스름돈 최소 개수가 대표적입니다. 큰 동전부터 고르는 그리디는 1,3,4원 같은 체계에서 최적이 아니고, 모든 조합을 고려하는 DP(coin change)로 풀어야 합니다. 0/1 배낭도 마찬가지로 가치/무게 비율로 그리디하게 담으면 최적이 보장되지 않아 DP가 필요합니다. 둘 다 국소 최적 선택이 전역 최적을 보장하지 않는 경우입니다."},
  {"id":"sc-algo-31","cat":"ALGO","level":"심화","q":"비트마스킹 DP에서 n의 현실적 상한은 대략 얼마이고 그 이유는 무엇인가요?","a":"대략 n ≤ 20 정도가 상한입니다. 외판원(TSP)류의 dp[mask][i]는 상태 수가 2^n × n인데, n=20이면 2^20≈10^6에 n을 곱해 수백만~수천만 수준이라 Java 1초 예산(약 10^8) 안에 들어옵니다. n이 더 커지면 상태 수가 지수로 폭발합니다. 또 원소가 32개를 넘으면 int 마스크(32비트)가 모자라 long 마스크를 써야 합니다."},
  {"id":"sc-algo-32","cat":"ALGO","level":"중급","q":"구간 합을 값 갱신이 잦은 상황에서 구해야 한다면 정적 누적합 대신 무엇을 쓰고 복잡도는 어떻게 되나요?","a":"세그먼트 트리나 펜윅 트리(BIT)를 씁니다. 정적 누적합(prefix sum)은 질의는 O(1)이지만 한 값만 바뀌어도 그 뒤를 전부 O(n)으로 재계산해야 해서 갱신이 잦으면 부적합합니다. 세그먼트 트리·펜윅은 점 갱신과 구간 질의를 각각 O(log n)에 처리하므로 갱신과 질의가 섞여 들어오는 상황에 적합합니다. 펜윅은 주로 구간 합, 세그먼트 트리는 합·최솟값·최댓값 같은 결합법칙 연산에 두루 씁니다."},
  {"id":"sc-algo-33","cat":"ALGO","level":"심화","q":"KMP가 단순 문자열 매칭(최악 O(nm))보다 빠른 이유를 실패 함수로 설명해 주세요.","a":"KMP는 패턴에 대해 실패 함수(각 위치까지의 '가장 긴 진접두사이면서 진접미사'의 길이)를 미리 계산합니다. 텍스트를 훑다가 불일치가 나면 텍스트 포인터는 되돌리지 않고, 실패 함수가 가리키는 위치로 패턴만 점프시켜 이미 매칭된 접두사 정보를 재활용합니다. 그래서 텍스트를 되감지 않아 전체가 O(n+m)이 되고, 매번 처음부터 다시 비교하는 단순 매칭의 최악 O(nm)을 피합니다."},
  {"id":"sc-algo-34","cat":"ALGO","level":"중급","q":"시간초과(TLE)가 났을 때 어떤 순서로 최적화를 점검하나요?","a":"알고리즘 → 자료구조 → 입출력 → 상수 순으로 점검합니다. 먼저 복잡도 자체가 입력 한계에 맞는지(예: O(n²)를 O(n log n)으로) 보고, 다음으로 적절한 자료구조(해시/힙/세그먼트 트리 등)로 바꿉니다. 그래도 빠듯하면 Scanner 대신 BufferedReader+StringTokenizer, 출력은 StringBuilder+BufferedWriter로 입출력을 최적화하고, 마지막으로 불필요한 연산·박싱 같은 상수 요인을 줄입니다."},
  {"id":"sc-algo-35","cat":"ALGO","level":"중급","q":"깊은 재귀 DFS가 StackOverflowError로 터질 때 대처 방법 두 가지는 무엇인가요?","a":"첫째, JVM 옵션 -Xss로 스레드 스택 크기를 키워 허용 재귀 깊이를 늘립니다. 둘째, 재귀를 명시적 스택(ArrayDeque)을 쓰는 반복 DFS로 변환해 JVM 호출 스택에 의존하지 않게 합니다. 입력이 일렬로 매우 깊어질 수 있는 그래프나 DP에서는 반복 변환이 더 근본적인 해결책입니다."},
  {"id":"sc-cs-1","cat":"CS","level":"기본","q":"프로세스와 스레드의 차이를 주소 공간 관점에서 설명해 주세요. 어떤 영역이 공유되고 어떤 영역이 분리됩니까?","a":"프로세스는 실행 중인 프로그램으로 독립된 주소 공간을 가지고, 스레드는 그 프로세스 안의 실행 흐름입니다. 코드(text)·데이터(전역/static)·힙은 스레드끼리 공유하고, 스택·레지스터·PC(프로그램 카운터)는 스레드별로 분리됩니다. 그래서 스레드는 생성이 가볍고 공유 메모리로 통신이 쉽지만, 한 스레드가 잘못된 메모리에 접근하면 주소 공간을 공유하는 프로세스 전체가 죽을 수 있습니다. Java 스레드도 같은 JVM 힙을 공유하므로 공유 변수 접근 시 동기화가 필요합니다."},
  {"id":"sc-cs-2","cat":"CS","level":"중급","q":"유저 모드와 커널 모드를 나누는 이유는 무엇이고, 둘 사이 전환은 언제 일어납니까?","a":"하드웨어 특권 명령을 응용이 직접 실행하지 못하게 막아 보호와 격리를 보장하기 위해 이중 모드를 둡니다. 유저 모드는 응용 코드를, 커널 모드는 특권 명령을 실행합니다. 전환은 응용이 파일·네트워크·프로세스 생성 같은 커널 기능을 시스템 콜로 요청할 때, 그리고 인터럽트나 예외(trap)가 발생할 때 일어납니다. 즉 응용이 직접 하드웨어를 만지지 않고 항상 커널을 거치도록 강제하는 구조입니다."},
  {"id":"sc-cs-3","cat":"CS","level":"중급","q":"시스템 콜은 인터럽트(trap)와 어떻게 연결됩니까?","a":"시스템 콜은 유저 프로세스가 커널 기능을 요청하는 인터페이스인데, 내부적으로 소프트웨어 인터럽트(trap)를 발생시켜 유저 모드에서 커널 모드로 전환합니다. trap은 명령 실행 중에 동기적으로 발생하는 소프트웨어 인터럽트라는 점에서 I/O 완료·타이머 같은 비동기 하드웨어 인터럽트와 구분됩니다. read/write/fork/exec 같은 호출이 이 경로로 커널에 진입합니다."},
  {"id":"sc-cs-4","cat":"CS","level":"심화","q":"Context Switching이 비싼 이유를 직접 비용과 간접 비용으로 나눠 설명해 주세요.","a":"Context Switching은 실행 중 프로세스의 컨텍스트를 PCB에 저장하고 다음 프로세스의 컨텍스트를 복원하는 과정입니다. 직접 비용은 레지스터·PC 등 상태를 저장하고 복원하는 작업 자체이고, 간접 비용은 전환 후 캐시와 TLB가 무효화되어 한동안 캐시 미스가 늘며 성능이 떨어지는 부분입니다. 그래서 단순한 저장·복원 시간보다 실제 체감 비용이 더 큽니다."},
  {"id":"sc-cs-5","cat":"CS","level":"중급","q":"PCB에는 무엇이 담기며, 같은 프로세스 내 스레드 전환이 프로세스 전환보다 싼 이유는 무엇입니까?","a":"PCB(Process Control Block)는 PID, PC, 레지스터 값, 메모리 정보, 열린 파일 목록 등 프로세스 상태를 담는 커널 자료구조입니다. 같은 프로세스 안의 스레드끼리는 주소 공간(코드·데이터·힙과 페이지 테이블)을 공유하기 때문에, 스레드 전환 시 페이지 테이블 교체나 TLB 무효화 부담이 작아 프로세스 전환보다 비용이 적게 듭니다."},
  {"id":"sc-cs-6","cat":"CS","level":"기본","q":"Race Condition이 무엇이고 counter++가 왜 위험한지, 어떻게 막는지 설명해 주세요.","a":"Race Condition은 둘 이상의 스레드가 공유 자원에 동시에 접근하고 적어도 하나가 수정해, 실행 순서(타이밍)에 따라 결과가 달라지는 상황입니다. counter++는 값을 읽고-수정하고-쓰는 read-modify-write 3단계라 원자적이지 않아서, 두 스레드가 끼어들면 증가가 유실될 수 있습니다. 임계 구역을 한 번에 하나만 들어가게 상호 배제로 보호하면 막을 수 있고, Java에서는 synchronized·ReentrantLock이나 AtomicInteger를 씁니다. JVM엔 GIL이 없어 멀티코어에서 진짜 병렬로 돌기 때문에 이 race가 또렷하게 재현됩니다."},
  {"id":"sc-cs-7","cat":"CS","level":"중급","q":"뮤텍스와 세마포어의 차이를 '소유권'(누가 해제할 수 있는가) 키워드로 설명해 주세요.","a":"뮤텍스는 소유권 개념이 있는 락으로, 잠근 스레드만 해제할 수 있고 한 번에 하나만 임계 구역에 진입합니다. 세마포어는 정수 카운터로 동시 접근 N개를 허용하고 소유권이 없어, 획득하지 않은 다른 주체도 signal(V)을 호출할 수 있습니다. 그래서 카운트 1인 binary semaphore가 뮤텍스와 비슷해 보여도 본질적 차이는 '소유권 유무'이며, 세마포어는 신호 전달이나 순서 제어에도 쓰입니다."},
  {"id":"sc-cs-8","cat":"CS","level":"중급","q":"데드락 발생 4조건을 모두 말하고, 그중 하나를 깨는 현실적 예방법을 들어 주세요.","a":"데드락은 상호 배제, 점유와 대기(hold and wait), 비선점, 환형 대기(circular wait) 네 조건이 동시에 모두 성립할 때 발생하며, 이 넷은 필요조건입니다. 현실적 예방법으로는 모든 주체가 자원을 같은 순서로 잡도록 락 획득 순서를 통일해 환형 대기를 깨는 방법이 대표적입니다. 그 외 회피(은행원 알고리즘)나 탐지 후 회복(victim 선정 롤백)도 있는데, DB 트랜잭션 데드락도 같은 원리이고 보통 DB 엔진이 탐지해 한쪽을 롤백시킵니다."},
  {"id":"sc-cs-9","cat":"CS","level":"중급","q":"선점 vs 비선점 스케줄링의 차이와, Round Robin의 타임 퀀텀이 너무 크거나 작을 때의 문제는 무엇입니까?","a":"비선점은 실행 중인 프로세스가 스스로 CPU를 놓을 때까지 뺏지 않는 방식(FCFS, 비선점 SJF)이고, 선점은 OS가 도중에 CPU를 회수하는 방식(Round Robin, 선점형 우선순위, MLFQ)입니다. Round Robin에서 타임 퀀텀이 너무 크면 FCFS처럼 동작해 응답시간이 나빠지고, 너무 작으면 Context Switching이 잦아져 오버헤드가 커집니다. 적절한 크기로 응답성과 오버헤드를 균형 잡아야 합니다."},
  {"id":"sc-cs-10","cat":"CS","level":"심화","q":"IPC 방식 중 공유 메모리와 메시지 전달의 트레이드오프는 무엇이고, 같은 프로세스 내 스레드는 왜 별도 IPC가 덜 필요합니까?","a":"공유 메모리는 두 프로세스가 같은 메모리 영역을 공유해 빠르지만 동기화를 직접 관리해야 합니다. 메시지 전달(파이프·메시지 큐·소켓·시그널)은 커널을 거쳐 데이터를 복사하므로 상대적으로 느리지만 동기화가 더 단순하고 격리가 좋습니다. 같은 프로세스 내 스레드는 이미 힙·데이터를 공유하므로 별도 IPC 메커니즘 없이 공유 변수로 통신할 수 있고, 다만 동시 접근에 대한 동기화는 여전히 필요합니다."},
  {"id":"sc-cs-11","cat":"CS","level":"기본","q":"페이징과 세그멘테이션의 차이를 내부/외부 단편화로 설명해 주세요.","a":"페이징은 메모리를 고정 크기 페이지로 나눠 외부 단편화가 없지만, 마지막 페이지가 다 안 차서 생기는 내부 단편화가 발생하며 페이지 테이블과 MMU가 필요합니다. 세그멘테이션은 코드·스택 같은 논리 단위로 가변 크기로 나눠 내부 단편화는 없지만 빈 공간이 흩어지는 외부 단편화가 생깁니다. 페이징의 페이지 테이블은 가상 페이지 번호를 물리 프레임 번호로 매핑합니다."},
  {"id":"sc-cs-12","cat":"CS","level":"중급","q":"page fault가 나는 과정과 페이지 교체 알고리즘이 필요한 이유를 설명해 주세요.","a":"접근하려는 페이지가 물리 메모리에 없으면 page fault가 발생하고, OS가 디스크에서 해당 페이지를 메모리로 가져옵니다(demand paging). 이때 물리 메모리가 가득 차 있으면 내보낼 victim 페이지를 골라야 하므로 교체 알고리즘이 필요합니다. 잘못 고르면 곧 다시 필요한 페이지를 내보내 fault가 폭증하는 thrashing이 생길 수 있습니다."},
  {"id":"sc-cs-13","cat":"CS","level":"심화","q":"LRU와 Optimal의 차이, 그리고 Belady's anomaly가 무엇이며 어떤 알고리즘에서 나타나는지 설명해 주세요.","a":"LRU는 가장 오래 안 쓴 페이지를 내보내는 방식으로, 과거 참조 기록(최근성)을 근거로 미래를 근사하며 좋은 성능을 내지만 매 접근마다 사용 시각을 추적해야 해 구현 비용이 큽니다. Optimal은 미래에 가장 늦게 쓰일 페이지를 내보내는 이론적 최적이지만 미래를 알 수 없어 실현 불가하고 비교 기준으로만 씁니다. Belady's anomaly는 프레임 수를 늘렸는데 오히려 page fault가 증가하는 현상으로, FIFO 같은 비스택 알고리즘에서만 나타나고 LRU·Optimal 같은 스택 알고리즘에서는 발생하지 않습니다."},
  {"id":"sc-cs-14","cat":"CS","level":"중급","q":"메모리 계층과 지역성(시간/공간)을 설명하고, 배열이 캐시 친화적인 이유를 말해 주세요.","a":"메모리는 레지스터→캐시(L1/L2/L3)→메인 메모리(RAM)→보조기억장치(디스크/SSD)로 갈수록 느리지만 싸고 용량이 커지는 계층 구조입니다. 시간 지역성(최근 쓴 데이터를 또 씀)과 공간 지역성(가까운 주소를 이어서 씀) 덕분에 캐시가 효과적입니다. 배열은 연속된 메모리에 저장되어 캐시 라인 단위로 한꺼번에 적재되므로, 노드가 흩어진 연결 리스트보다 순회 시 캐시 적중률이 높아 캐시 친화적입니다."},
  {"id":"sc-cs-15","cat":"CS","level":"중급","q":"파일 시스템에서 inode와 디렉터리, 파일 디스크립터의 역할은 각각 무엇입니까?","a":"inode는 Unix 계열에서 파일의 메타데이터와 데이터 블록 포인터를 담는 구조로, 파일 이름이 아니라 파일 실체를 가리킵니다. 디렉터리는 파일 이름과 그 메타데이터(inode)를 묶는 구조로 보통 트리 형태입니다. 파일 디스크립터는 프로세스가 열린 파일을 가리키는 정수 핸들로, 응용은 이 정수로 read/write 같은 연산을 수행합니다."},
  {"id":"sc-cs-16","cat":"CS","level":"기본","q":"OSI 7계층을 순서대로 말하고 HTTP/TCP/IP/이더넷을 각각 배치해 주세요.","a":"아래에서부터 물리(1)·데이터링크(2)·네트워크(3)·전송(4)·세션(5)·표현(6)·응용(7) 계층입니다. HTTP는 응용 계층, TCP와 UDP는 전송 계층, IP는 네트워크 계층, 이더넷은 데이터링크 계층에 배치됩니다. 각 계층이 독립적이라 하위 계층이 바뀌어도 상위에 영향이 없고, 실무에서 쓰는 TCP/IP 4계층(또는 5계층) 모델과 대응됩니다."},
  {"id":"sc-cs-17","cat":"CS","level":"중급","q":"TCP 연결이 3-way, 종료가 4-way인 이유를 각각 설명해 주세요.","a":"연결 수립은 SYN → SYN+ACK → ACK의 3단계인데, 양방향 시퀀스 번호를 합의하고 양쪽의 송수신 능력을 확인하는 데 3번이면 충분하기 때문입니다. 종료는 FIN → ACK → FIN → ACK의 4단계인데, 양쪽이 독립적으로 자기 방향을 닫기 때문입니다. 한쪽이 FIN을 보내도 상대는 아직 보낼 데이터가 남아 있을 수 있어 ACK와 자신의 FIN을 따로 보내므로 단계가 하나 더 늘어납니다."},
  {"id":"sc-cs-18","cat":"CS","level":"심화","q":"TIME_WAIT는 왜 존재하며(2MSL 동안 무엇을 대비?), 많이 쌓이면 무엇이 문제입니까?","a":"능동 종료(active close) 측은 종료 후 2MSL 동안 TIME_WAIT 상태에 머뭅니다. 첫째로 마지막 ACK가 유실되면 상대가 FIN을 재전송할 수 있어 이를 받아 다시 ACK하기 위해서이고, 둘째로 이전 연결의 지연 패킷이 같은 포트로 맺은 새 연결에 섞이는 것을 막기 위해서입니다. 다만 TIME_WAIT 소켓이 너무 많이 쌓이면 로컬 포트와 소켓 자원이 고갈되어 새 연결을 맺기 어려워집니다."},
  {"id":"sc-cs-19","cat":"CS","level":"중급","q":"흐름 제어와 혼잡 제어의 차이를 '보호 대상' 기준으로 설명해 주세요.","a":"흐름 제어는 보호 대상이 수신자입니다. 수신 버퍼가 감당할 수 있는 양만큼만 보내도록 수신 윈도우(rwnd)와 슬라이딩 윈도우로 송신량을 조절합니다. 혼잡 제어는 보호 대상이 네트워크 전체입니다. 혼잡 윈도우(cwnd)를 slow start·congestion avoidance·fast retransmit/fast recovery, 즉 AIMD 방식으로 조절해 망의 혼잡을 막습니다. '수신자 보호냐 네트워크 보호냐'가 둘을 가르는 핵심입니다."},
  {"id":"sc-cs-20","cat":"CS","level":"기본","q":"TCP와 UDP의 차이와, UDP가 적합한 사례를 설명해 주세요.","a":"TCP는 연결을 맺고(핸드셰이크) 재전송·순서 보장·흐름/혼잡 제어를 제공해 신뢰성이 높지만 오버헤드가 있습니다. UDP는 비연결형으로 이런 보장이 없어 헤더가 작고 가볍고 빠릅니다. 그래서 실시간 스트리밍, 게임, DNS처럼 약간의 손실보다 속도와 낮은 지연이 중요한 경우에 적합합니다. DNS는 기본 UDP를 쓰되 응답이 버퍼 한계를 넘어 truncated(TC 비트)되면 클라이언트가 TCP로 재질의합니다."},
  {"id":"sc-cs-21","cat":"CS","level":"기본","q":"대칭키와 공개키의 차이와 각각의 장단점은 무엇입니까?","a":"대칭키는 암호화와 복호화에 같은 키를 써서 빠르지만, 키를 상대에게 안전하게 전달하는 키 분배 문제가 있습니다. 공개키(비대칭키)는 공개키로 암호화하면 개인키로만 복호화되고(반대로 개인키 서명은 공개키로 검증) 키 분배 문제는 해결되지만 연산이 느립니다. 그래서 실제 프로토콜은 공개키로 신원 인증과 키 합의를 처리하고 본 통신은 빠른 대칭키로 하는 하이브리드 구조를 씁니다."},
  {"id":"sc-cs-22","cat":"CS","level":"중급","q":"HTTPS는 무엇을 보장하고 무엇을 보장하지 못합니까?","a":"HTTPS는 HTTP 아래에 TLS 계층을 둬서 암호화로 기밀성(도청 방지), 무결성(변조 방지), 서버 인증(서버 위장 방지)을 보장합니다. 반면 엔드포인트 자체의 취약점이나, 사용자가 스스로 공격자 사이트에 정상 접속해 정보를 넘기는 피싱 같은 공격은 막지 못합니다. 즉 전송 구간은 보호하지만 양 끝단의 보안 문제까지 해결해 주지는 않습니다."},
  {"id":"sc-cs-23","cat":"CS","level":"심화","q":"TLS handshake에서 인증서로 신원을 검증하면서 세션키를 합의하는 과정을 설명해 주세요.","a":"먼저 ClientHello/ServerHello로 TLS 버전과 암호 스위트를 합의하고, 서버가 공개키가 담긴 인증서를 보내면 클라이언트가 CA 신뢰 체인으로 서버 신원을 검증합니다. 현대 TLS는 ECDHE로 키를 교환해 양측이 같은 세션키(대칭키)를 각자 계산해 도출하며, 이때 인증서의 키는 세션키 암호화가 아니라 서명 검증, 즉 인증에 쓰입니다. 이후에는 빠른 대칭키로 본 통신을 암호화하고, ECDHE는 순방향 비밀성(PFS)도 제공합니다."},
  {"id":"sc-cs-24","cat":"CS","level":"중급","q":"공개키만으로 통신하지 않고 대칭키를 따로 합의(또는 도출)하는 이유는 무엇입니까?","a":"공개키 암호는 키 분배 문제를 해결해 주지만 연산이 느려서 모든 데이터를 공개키로 주고받기엔 비효율적입니다. 그래서 공개키는 신원 인증과 키 합의에만 쓰고, 실제 대량 데이터 통신은 빠른 대칭키로 처리하는 하이브리드 구조를 씁니다. 세션키를 공개키로 암호화해 전달하는 RSA 키 전송은 옛 방식이고, TLS 1.3은 (EC)DHE로 양측이 세션키를 각자 계산해 도출합니다."},
  {"id":"sc-cs-25","cat":"CS","level":"중급","q":"인증서로 서버 신원을 검증하는 원리(CA·신뢰 체인)는 무엇입니까?","a":"서버 인증서에는 서버의 공개키와 도메인 정보가 담겨 있고, 신뢰할 수 있는 CA(인증 기관)가 그 인증서에 서명합니다. 클라이언트는 자신이 신뢰하는 루트 CA부터 중간 CA를 거쳐 서버 인증서까지 이어지는 신뢰 체인을 따라 서명을 검증해, 인증서가 위조되지 않았고 해당 도메인의 정당한 서버임을 확인합니다. 이렇게 CA에 대한 신뢰가 서버 신원에 대한 신뢰로 연결됩니다."},
  {"id":"sc-cs-26","cat":"CS","level":"기본","q":"L4와 L7 로드 밸런서의 차이는 무엇이고, 쿠키/URL 기반 라우팅은 어느 쪽입니까?","a":"L4 로드 밸런서는 전송 계층에서 IP와 포트 정보만으로 트래픽을 분산하고, L7 로드 밸런서는 응용 계층에서 URL·헤더·쿠키 같은 내용을 보고 분산합니다. 따라서 쿠키나 URL 기반 라우팅은 내용을 들여다봐야 하므로 L7입니다. 분배 알고리즘으로는 라운드로빈·least connection·해시 등이 있고, 같은 클라이언트를 같은 서버로 보내는 sticky session도 L7에서 흔히 씁니다. Nginx 같은 리버스 프록시가 L7 LB와 TLS 종료를 맡습니다."},
  {"id":"sc-cs-27","cat":"CS","level":"심화","q":"Blocking/Non-blocking과 Synchronous/Asynchronous를 각각 다른 축으로 설명해 주세요.","a":"이 둘은 서로 다른 질문입니다. Blocking/Non-blocking은 호출이 작업이 끝날 때까지 제어권을 잡아두느냐, 즉시 돌려주느냐 하는 제어 흐름·대기 방식의 문제입니다. Sync/Async는 작업 완료를 호출자가 직접 확인·대기하느냐, 콜백이나 이벤트로 통지받느냐 하는 완료 처리·통지 방식의 문제입니다. 그래서 sync-blocking, sync-non-blocking, async-blocking, async-non-blocking 네 조합이 가능하며, 핵심은 '블로킹=제어권을 안 돌려주고 대기, 동기=완료를 호출자가 직접 챙김'입니다."},
  {"id":"sc-cs-28","cat":"CS","level":"중급","q":"Blocking I/O의 요청당 스레드 모델이 가진 한계(C10K)는 무엇이며, I/O 멀티플렉싱(epoll)은 이와 어떻게 다릅니까?","a":"Blocking I/O는 read/accept에서 데이터가 준비될 때까지 호출 스레드가 멈추므로, 연결마다 스레드를 하나씩 붙이는 요청당 스레드 모델이 됩니다. 동시 연결이 수만 개로 늘면 스레드 수와 Context Switching 비용이 폭증하는 C10K 문제가 생깁니다. Non-blocking I/O는 준비가 안 되면 즉시 반환하고, select/poll/epoll 같은 I/O 멀티플렉싱으로 한 스레드가 다수 소켓을 감시하는 이벤트 루프를 구성해 적은 스레드로 많은 연결을 처리합니다."},
  {"id":"sc-cs-29","cat":"CS","level":"심화","q":"Servlet(Tomcat) thread-per-request와 Spring WebFlux(Netty) 이벤트 루프의 차이는 무엇이고, 비동기 서버가 유리한 워크로드는 무엇입니까?","a":"Servlet 컨테이너인 Tomcat은 요청마다 워커 스레드를 할당하는 thread-per-request 블로킹 모델이라, I/O를 기다리는 동안 스레드가 묶여 동시 연결이 많아지면 스레드 풀이 고갈됩니다. Spring WebFlux는 Netty 기반 이벤트 루프로 적은 수의 논블로킹 스레드가 다수 연결을 비동기로 처리합니다. 따라서 외부 API 호출이나 DB 대기처럼 I/O 바운드이면서 동시 연결이 많은 워크로드에서 비동기·논블로킹 서버가 적은 스레드로 높은 처리량을 내며 유리합니다."},
  {"id":"sc-arch-1","cat":"ARCH","level":"기본","q":"단일 책임 원칙(SRP)에서 말하는 '책임' 혹은 '변경의 이유'란 무엇이고, 흔히 말하는 'actor(액터)'와는 어떤 관계인가요?","a":"SRP의 책임은 '클래스가 변경되어야 하는 이유'를 뜻하고, 그 변경을 요구하는 주체(actor)가 곧 책임의 기준입니다. 예를 들어 한 클래스가 회계 부서의 요구와 운영 부서의 요구를 동시에 담고 있으면 서로 다른 actor가 같은 클래스를 변경 사유로 갖게 되어 SRP 위반입니다. 즉 '하나의 클래스는 하나의 actor에 대해서만 변경 책임을 진다'로 이해하고, actor가 갈리는 지점에서 클래스를 분리해야 합니다."},
  {"id":"sc-arch-2","cat":"ARCH","level":"중급","q":"DIP와 DI는 어떻게 다른가요? 원칙과 구현 기법의 차이를 설명하고, DI 컨테이너 없이도 DIP를 지킬 수 있는지 말씀해 주세요.","a":"DIP는 고수준 모듈이 추상화에 의존하도록 의존성을 역전시키는 '설계 원칙'이고, DI는 그 의존을 외부에서 주입하는 '구현 기법', IoC는 제어의 역전이라는 더 넓은 개념입니다. Spring은 IoC 컨테이너가 빈을 관리하며 생성자 주입으로 DI를 수행하지만, DI 컨테이너가 DIP의 필수 조건은 아닙니다. 컨테이너 없이도 생성자나 팩토리로 추상화에 직접 주입하면 DIP는 지킬 수 있고, 컨테이너는 편의 수단일 뿐입니다. 참고로 필드 @Autowired보다 생성자 주입이 불변성과 테스트 용이성 면에서 권장됩니다."},
  {"id":"sc-arch-3","cat":"ARCH","level":"중급","q":"구현체가 하나뿐인데도 인터페이스를 두는 것이 정당한 경우와, 반대로 과설계가 되는 경우를 구분해서 설명해 주세요.","a":"구현체가 하나여도 고수준 모듈을 외부 세부사항에서 격리하려는 목적이 분명하면 인터페이스가 정당합니다. 예를 들어 도메인이 정의한 포트를 두고 어댑터(JPA Repository 등)가 구현하게 해 DIP를 지키거나, 테스트에서 fake로 대체하거나, 향후 교체 가능성이 본질적일 때입니다. 반대로 단순 위임만 하는 인터페이스를 '언젠가 바뀔지 몰라서' 기계적으로 만들면 YAGNI 위반이자 추상화 비용만 늘리는 과설계입니다. 좋은 추상화는 변경을 격리해 주는 값이 그 비용을 넘을 때 정당합니다."},
  {"id":"sc-arch-4","cat":"ARCH","level":"기본","q":"전략 패턴은 어떤 객체지향 설계 원칙을 실현하나요?","a":"전략 패턴은 OCP와 DIP를 실현합니다. 행위를 인터페이스(전략)로 추상화하고 구현을 갈아끼우게 하면, 새 전략을 추가할 때 기존 코드를 수정하지 않고 확장만 하므로 OCP를 만족합니다. 또 클라이언트가 구체 구현이 아니라 전략 추상화에 의존하므로 DIP도 지켜집니다. 실무에서는 결제수단 분기 같은 if-else 덩어리를 전략으로 치환해 확장에 열고 변경에 닫는 형태로 적용합니다."},
  {"id":"sc-arch-5","cat":"ARCH","level":"중급","q":"DRY 원칙을 잘못 적용해서 오히려 결합도가 높아진 사례를 설명해 주세요.","a":"우연히 같아 보이는 코드(우연한 중복)를 본질적 중복으로 착각해 무리하게 한 곳으로 합치면, 사실은 다른 이유로 변하는 두 관심사가 한 추상화에 묶여 결합도가 올라갑니다. 예를 들어 주문 검증과 배송 검증이 지금은 같은 로직이라 공통 메서드로 합쳤는데, 이후 한쪽 규칙만 바뀌면 공유 코드가 양쪽에 끌려다니며 분기와 플래그가 늘어납니다. DRY는 '본질적으로 같은 지식'에만 적용해야 하고, 우연한 중복은 차라리 중복을 허용하는 편이 결합을 낮춥니다."},
  {"id":"sc-arch-6","cat":"ARCH","level":"중급","q":"레이어드 아키텍처는 Controller→Service→Repository로 의존 방향이 단방향인데도, 어째서 도메인이 DB(영속성)에 의존하게 되나요?","a":"호출 방향은 단방향이지만, Service가 JPA @Entity를 그대로 도메인 모델로 쓰면 도메인 규칙이 영속성 매핑에 의존하게 됩니다. @Entity가 영속성 매핑과 도메인 모델을 겸하기 때문에, 컬럼 매핑·지연 로딩·연관관계 같은 영속성 관심사가 도메인 안으로 새어 들어옵니다. 결과적으로 의존 방향과 무관하게 도메인이 프레임워크/DB에 끌려다니게 되고, 이를 끊으려면 도메인 객체를 POJO로 두고 JPA 엔티티와 분리해 매핑해야 합니다."},
  {"id":"sc-arch-7","cat":"ARCH","level":"중급","q":"Anemic Domain Model(빈약한 도메인 모델)이 안티패턴으로 불리는 이유는 무엇이고, 반대로 그것이 정당한 경우는 언제인가요?","a":"빈약한 도메인은 데이터(엔티티)는 getter/setter만 갖고 모든 로직이 Service로 빠져나간 형태라, 캡슐화가 깨지고 불변식이 한곳에 모이지 못해 fat Service가 생기고 규칙이 흩어집니다. 그래서 도메인 모델을 의도한 설계에서는 안티패턴입니다. 다만 모든 프로젝트에 도메인 모델이 답은 아니며, 로직이 거의 없는 단순 CRUD나 트랜잭션 스크립트로 충분한 경우에는 빈약한 모델이 오히려 단순하고 적절할 수 있습니다."},
  {"id":"sc-arch-8","cat":"ARCH","level":"중급","q":"도메인 로직을 DB 없이 단위 테스트하지 못하게 만드는 구조적 원인은 무엇인가요?","a":"도메인 로직이 JPA 엔티티에 의존하면 테스트 시 EntityManager나 실제 DB가 있어야 객체를 구성·검증할 수 있어 단위 테스트가 통합 테스트로 변질됩니다. 즉 도메인이 영속성에 결합돼 있는 것이 구조적 원인입니다. 도메인 객체를 순수 POJO로 두고 영속성은 어댑터로 밀어내 의존 방향을 분리하면, DB나 프레임워크 없이도 도메인 규칙을 빠르게 단위 테스트할 수 있습니다."},
  {"id":"sc-arch-9","cat":"ARCH","level":"중급","q":"Spring과 JPA의 관행이 어떻게 fat Service와 빈약한 도메인을 유도하며, 이를 어떻게 완화할 수 있나요?","a":"Spring은 로직을 @Service/@Controller로 모으도록 유도하고, JPA @Entity가 영속성 매핑과 도메인 모델을 겸하며, DTO가 검증까지 겸하는 관행이 겹쳐 로직이 Service로 몰리고 엔티티는 데이터 홀더로 전락합니다. 그 결과 fat Service/fat Controller와 빈약한 도메인이 생깁니다. 완화책은 흩어진 도메인 규칙을 애그리거트(도메인 객체)의 메서드로 끌어와 응집시키고, 도메인 모델과 JPA 엔티티를 분리하며, 형식 검증은 DTO에 두되 불변식은 도메인 안에서 강제하는 것입니다."},
  {"id":"sc-arch-10","cat":"ARCH","level":"심화","q":"모든 프로젝트에 헥사고날이나 DDD를 적용하지 않는 이유는 무엇이고, 적용 여부의 판단 기준은 무엇인가요?","a":"헥사고날/DDD는 포트·어댑터·도메인 분리, 매핑 코드 등 구조적 비용이 큽니다. 도메인 복잡도가 낮은 단순 CRUD에서는 트랜잭션 스크립트로 충분하고 오히려 보일러플레이트만 늘어 과설계가 됩니다. 판단 기준은 도메인 규칙과 불변식의 복잡도, 변경·확장 빈도, 외부 시스템 격리 필요성입니다. 핵심 비즈니스 로직이 복잡하고 오래 진화하는 코어 도메인이면 투자가 정당하지만, 보조·제네릭 영역이나 단순 데이터 처리에는 가벼운 구조가 낫습니다."},
  {"id":"sc-arch-11","cat":"ARCH","level":"기본","q":"헥사고날 아키텍처에서 인바운드 포트와 아웃바운드 포트는 각각 무엇이며, 누가 그 포트를 구현하나요?","a":"인바운드 포트는 외부가 애플리케이션을 호출하는 유스케이스 인터페이스로, 애플리케이션 서비스가 이를 구현하고 인바운드 어댑터(@RestController, 리스너)가 호출합니다. 아웃바운드 포트는 애플리케이션이 외부(저장소, 외부 API)를 호출하기 위해 도메인/애플리케이션 쪽이 정의한 인터페이스로, 아웃바운드 어댑터(JPA Repository, HTTP 클라이언트)가 구현합니다. 핵심은 의존성이 항상 안쪽을 향하도록 포트를 안쪽에서 정의하고 바깥 어댑터가 구현하게 만드는 것입니다."},
  {"id":"sc-arch-12","cat":"ARCH","level":"중급","q":"도메인 객체와 JPA 엔티티를 분리할 때의 득과 실을 설명해 주세요.","a":"분리하면 도메인이 순수 POJO가 되어 Spring/JPA에 의존하지 않으므로 DB 없이 빠르게 단위 테스트할 수 있고, 영속성 매핑 변경이 도메인 규칙에 새어 들지 않으며 불변식을 도메인 안에 응집할 수 있습니다. 대신 도메인↔엔티티 toDomain/toEntity 매핑 코드와 두 모델을 유지하는 비용이 듭니다. 그래서 도메인 복잡도가 낮으면 분리 비용이 더 클 수 있고, 규칙이 풍부한 코어 도메인일수록 분리의 이득이 커집니다."},
  {"id":"sc-arch-13","cat":"ARCH","level":"중급","q":"애플리케이션 서비스와 도메인 서비스는 어떻게 다르고, 트랜잭션 경계는 어디에 두어야 하나요?","a":"애플리케이션 서비스는 유스케이스를 조율하는 계층으로 트랜잭션 관리, DTO 변환, 포트 호출 순서를 담당하지만 도메인 규칙 자체는 갖지 않습니다. 도메인 서비스는 한 애그리거트에 넣기 애매한 순수 도메인 규칙을 담는 계층입니다. 트랜잭션 경계는 유스케이스 단위인 애플리케이션 서비스에 두며, Spring에서는 @Transactional을 애플리케이션 서비스 메서드에 붙이고 @RestController는 얇게 유지합니다."},
  {"id":"sc-arch-14","cat":"ARCH","level":"중급","q":"Spring Data JPA Repository를 헥사고날의 아웃바운드 어댑터로 두려면 어떻게 구성하나요?","a":"포트(예: OrderRepository 인터페이스)는 도메인/애플리케이션 안쪽에서 정의하고, 그 구현을 persistence 어댑터에서 Spring Data JPA로 작성합니다. 어댑터 안에서 도메인 객체와 JPA @Entity를 toDomain/toEntity로 매핑해, 애플리케이션 서비스는 도메인이 정의한 포트에만 의존하고 Spring Data JPA 인터페이스에는 직접 의존하지 않게 합니다. 이렇게 하면 의존성이 안쪽을 향하고, 포트 구현을 인메모리 fake로 갈아끼워 테스트할 수도 있습니다."},
  {"id":"sc-arch-15","cat":"ARCH","level":"중급","q":"헥사고날 구조에서 도메인을 DB 없이 테스트할 수 있는 이유는 무엇인가요?","a":"의존성이 항상 안쪽을 향하도록 설계해 도메인이 순수 POJO/POKO로 Spring·JPA에 의존하지 않기 때문입니다. 영속성·웹 같은 외부 관심사는 어댑터로 밀려나 있고, 도메인은 아웃바운드 포트라는 추상화에만 의존합니다. 따라서 테스트에서 포트를 인메모리 fake로 주입하면 EntityManager나 실제 DB 없이도 도메인 규칙과 불변식을 빠르게 검증할 수 있습니다."},
  {"id":"sc-arch-16","cat":"ARCH","level":"심화","q":"도메인 불변식 검증을 웹 요청 DTO에 넣으면 어떤 문제가 생기나요? 검증 계층은 어떻게 나눠야 할까요?","a":"불변식을 웹 DTO에 두면 도메인의 핵심 규칙이 바깥 어댑터에 새어 나가, 그 진입점을 거치지 않는 다른 경로(이벤트 리스너, 배치 등)에서는 규칙이 보장되지 않고 캡슐화가 깨집니다. 따라서 형식·필수값 같은 검증은 DTO에서 Bean Validation(@Valid)으로 하고, 비즈니스 불변식은 반드시 도메인 객체 안에서 강제해야 합니다. 그래야 어떤 경로로 들어와도 도메인이 자기 규칙을 스스로 지키고, 요청 검증과 도메인 검증의 책임이 분리됩니다."},
  {"id":"sc-arch-17","cat":"ARCH","level":"기본","q":"DDD에서 엔티티와 값 객체(VO)는 동일성 판단이 어떻게 다르고, VO를 불변으로 두는 이유는 무엇인가요?","a":"엔티티는 식별자(ID)로 동일성을 판단하고 상태가 가변이며 생명주기 동안 같은 ID면 같은 객체로 봅니다. VO는 식별자가 없고 Money나 Email처럼 값 자체로 동등성을 판단합니다. VO를 불변으로 두는 이유는, 값이 공유·재사용돼도 안전하고 스레드 안전하며 해시 키로 쓸 수 있고 의도치 않은 상태 변경으로 인한 버그를 막기 때문입니다. Java에서는 record나 불변 클래스, Kotlin에서는 data class로 VO를 표현할 수 있습니다."},
  {"id":"sc-arch-18","cat":"ARCH","level":"중급","q":"애그리거트 경계를 정하는 기준은 무엇이고, '트랜잭션당 애그리거트 하나' 규칙이 왜 중요한가요?","a":"애그리거트 경계는 함께 변해야 하는 불변식을 단위로 묶고, 외부는 애그리거트 루트를 통해서만 접근하게 정합니다. 한 트랜잭션에서 하나의 애그리거트만 수정하라는 규칙이 중요한 이유는, 그 안에서만 강한 일관성을 보장하고 애그리거트 간에는 최종 일관성으로 두어야 락 경합과 동시성 성능 문제가 줄기 때문입니다. 한 트랜잭션이 여러 애그리거트를 잠그면 락 범위가 넓어지고 충돌·데드락 위험이 커지므로, 작게 설계하는 것이 성능과 직결됩니다."},
  {"id":"sc-arch-19","cat":"ARCH","level":"중급","q":"애그리거트 사이를 객체 참조 대신 ID 참조로 두는 이유는 무엇인가요?","a":"애그리거트 4규칙 중 하나로, 다른 애그리거트는 직접 객체로 물지 않고 ID로만 참조합니다. 그래야 애그리거트 경계가 분명해지고 한 트랜잭션이 자기 애그리거트만 로드·수정하게 되어 '트랜잭션당 하나' 규칙을 지킬 수 있습니다. 또 객체 그래프가 무한정 끌려 들어오는 것을 막아 로딩 범위와 락 범위를 통제하고, 애그리거트 간 변경은 도메인 이벤트로 최종 일관성 있게 전파할 수 있습니다."},
  {"id":"sc-arch-20","cat":"ARCH","level":"중급","q":"도메인 서비스와 애플리케이션 서비스는 어떻게 구분하나요?","a":"도메인 서비스는 특정 엔티티나 VO에 넣기 애매한 순수 도메인 규칙을 담는 곳으로, 비즈니스 로직만 갖고 트랜잭션이나 인프라를 모릅니다. 애플리케이션 서비스는 유스케이스를 조율하는 계층으로 트랜잭션 경계 관리, DTO 변환, 포트 호출 순서 같은 흐름 제어를 담당하되 도메인 규칙 자체는 갖지 않습니다. 한마디로 도메인 서비스는 '무엇이 규칙인가', 애플리케이션 서비스는 '그 규칙들을 어떤 순서로 엮어 한 트랜잭션으로 처리하는가'를 책임집니다."},
  {"id":"sc-arch-21","cat":"ARCH","level":"중급","q":"도메인 이벤트는 옵저버 패턴과 어떤 관계이며, 이벤트를 트랜잭션 커밋 전에 발행하는 것과 후에 발행하는 것의 트레이드오프는 무엇인가요?","a":"도메인 이벤트는 옵저버 패턴의 도메인 버전으로, OrderPlaced 같은 사실을 발행하면 관심 있는 핸들러가 반응합니다. 커밋 전에 처리하면 같은 트랜잭션 안이라 원자적이지만, 핸들러가 실패하면 본래 작업까지 롤백되고 외부 부수효과를 되돌리기 어렵습니다. 커밋 후 발행은 본 작업의 정합성을 우선 보장하지만, 발행 직전 장애 시 이벤트 유실 위험이 있어 outbox 등으로 보완해야 합니다. 그래서 기본은 커밋 후 발행이고, 신뢰성이 필요하면 Transactional Outbox와 연결합니다."},
  {"id":"sc-arch-22","cat":"ARCH","level":"심화","q":"Spring의 @TransactionalEventListener(phase=AFTER_COMMIT)로 이벤트를 발행하는 방식의 장점과 위험은 무엇인가요?","a":"장점은 트랜잭션이 실제로 커밋된 뒤에만 핸들러가 실행되도록 보장해, 롤백된 작업에 대해 잘못된 후속 처리(메일 발송, 포인트 적립 등)가 일어나는 것을 막는다는 점입니다. ApplicationEventPublisher로 발행하고 AFTER_COMMIT 리스너로 받으면 발행 시점 문제를 깔끔히 처리할 수 있습니다. 위험은 커밋 후 별도 처리라 그 사이 장애 시 이벤트가 유실될 수 있고, 이벤트를 남발하면 모듈 간 결합이 숨고 흐름 추적이 어려워진다는 점입니다. 신뢰 전달이 필요하면 outbox로 보강해야 합니다."},
  {"id":"sc-arch-23","cat":"ARCH","level":"중급","q":"도메인 불변식 검증과 형식 검증을 분리하는 이유는 무엇인가요?","a":"둘은 책임과 위치가 다릅니다. 형식 검증은 입력값의 타입·필수·길이 같은 표면적 규칙으로 웹 경계의 DTO에서 Bean Validation(@Valid)으로 처리하는 게 적절합니다. 불변식은 '합계는 라인 합과 같아야 한다' 같은 비즈니스 규칙으로 반드시 도메인 객체 안에서 강제해야, 어떤 진입 경로로 들어와도 도메인이 스스로 규칙을 지킵니다. 분리하면 형식 오류와 비즈니스 위반의 에러 흐름이 구분되고, 도메인 규칙이 특정 어댑터에 종속되지 않습니다."},
  {"id":"sc-arch-24","cat":"ARCH","level":"기본","q":"바운디드 컨텍스트와 마이크로서비스는 어떤 관계인가요?","a":"바운디드 컨텍스트는 하나의 모델과 유비쿼터스 언어가 일관되게 통하는 논리적 경계로, 같은 '상품'도 주문·재고·카탈로그 컨텍스트에서 다른 모델을 가질 수 있음을 인정하는 개념입니다. 마이크로서비스는 그 경계를 물리적으로 분리해 배포하는 한 가지 방법일 뿐입니다. 즉 컨텍스트 경계가 MSA 분리의 후보 기준이 되지만, 같은 경계를 모듈러 모놀리스의 모듈/패키지로 표현해도 됩니다. 컨텍스트는 모델 경계, 마이크로서비스는 배포 단위라는 점이 다릅니다."},
  {"id":"sc-arch-25","cat":"ARCH","level":"중급","q":"같은 '회원'이나 '상품'을 컨텍스트마다 다른 모델로 두는 이유는 무엇이고, 전사 단일 모델로 통합하면 어떤 위험이 있나요?","a":"같은 용어라도 컨텍스트마다 관심사가 다릅니다. 주문에서의 상품은 가격·수량이 중요하고, 재고에서는 위치·수량, 카탈로그에서는 설명·이미지가 중요하므로 각 컨텍스트가 필요한 모델만 갖는 게 맞습니다. 이를 무리하게 단일 모델로 통합하면 모든 컨텍스트의 속성이 한 거대 모델에 몰려 결합도가 폭발하고, 한쪽 변경이 전체에 파급되며 유비쿼터스 언어가 모호해집니다. 컨텍스트별로 모델을 나누고 경계에서 변환하는 편이 안전합니다."},
  {"id":"sc-arch-26","cat":"ARCH","level":"중급","q":"ACL(Anti-Corruption Layer)은 무엇을 막아주며, 어디에 위치시키나요?","a":"ACL은 외부 시스템이나 다른 컨텍스트의 모델·용어가 우리 도메인으로 그대로 새어 들어와 모델을 오염시키는 것을 막는 변환 계층입니다. 예를 들어 PG사 응답 구조를 우리 도메인 모델로 번역해, 외부 포맷 변경이 도메인에 직접 영향을 주지 않게 합니다. 위치는 우리 컨텍스트의 경계, 보통 아웃바운드 어댑터 쪽에 두어 외부와 도메인 사이에서 변환을 수행하고, 도메인은 외부 모델을 모르게 유지합니다."},
  {"id":"sc-arch-27","cat":"ARCH","level":"중급","q":"Core/Supporting/Generic 서브도메인은 무엇이고, 노력은 어떻게 배분해야 하나요?","a":"Core는 경쟁력의 핵심이 되는 도메인, Supporting은 핵심을 돕지만 차별성은 낮은 도메인, Generic은 어디서나 비슷한 범용 도메인입니다. 가장 뛰어난 인력과 정교한 설계(DDD)는 Core에 집중해 직접 정성껏 만들어야 합니다. Generic은 가능하면 사오거나(buy) 기성 솔루션을 쓰고, Supporting은 그 중간에서 적당한 비용으로 처리합니다. 즉 build vs buy 결정을 서브도메인 분류로 내리고, 모든 영역에 같은 노력을 쏟지 않는 것이 핵심입니다."},
  {"id":"sc-arch-28","cat":"ARCH","level":"심화","q":"모놀리식부터 시작하는 것과 처음부터 MSA로 가는 것 중 무엇을 권하며, 그 근거와 위험은 무엇인가요?","a":"도메인 경계가 아직 불확실한 초기에는 모듈러 모놀리스로 시작하는 편이 안전합니다. 성급한 MSA는 잘못 그은 컨텍스트 경계를 네트워크로 굳혀, 분산 트랜잭션·운영 복잡도·배포 부담을 떠안으면서도 경계 재조정이 매우 어려워지는 위험이 있습니다. 모듈러 모놀리스로 경계를 코드(패키지/모듈)로 먼저 검증하고, 확장·조직·배포 독립성 요구가 분명해진 컨텍스트만 점진적으로 MSA로 떼어내는 것이 근거 있는 진화 경로입니다."},
  {"id":"sc-arch-29","cat":"ARCH","level":"중급","q":"바운디드 컨텍스트를 Gradle 멀티모듈이나 패키지 경계로 표현하면서, 모듈 간 결합을 끊으려면 어떻게 해야 하나요?","a":"각 컨텍스트를 Gradle 멀티모듈이나 top-level 패키지로 분리해 경계를 코드 구조로 드러냅니다. 모듈 간에 JPA @Entity나 Repository를 직접 import해서 참조하면 영속성·내부 모델이 새어 결합이 강해지므로 이를 금지합니다. 대신 공개 인터페이스(포트)나 도메인 이벤트를 통해서만 상호작용하게 해 내부 구현을 감추고, 컴파일 의존성 자체로 경계 위반을 막습니다. 이렇게 하면 컨텍스트가 독립적으로 진화할 수 있고 나중에 MSA로 떼어내기도 쉽습니다."},
  {"id":"sc-arch-30","cat":"ARCH","level":"기본","q":"유비쿼터스 언어가 깨지면 어떤 문제가 생기나요?","a":"유비쿼터스 언어는 도메인 전문가와 개발자가 같은 용어를 같은 의미로 쓰자는 약속입니다. 이것이 깨져 코드의 이름과 업무 용어가 어긋나면, 같은 단어를 서로 다르게 해석해 요구사항이 잘못 구현되는 버그와 끝없는 소통 비용이 발생합니다. 또 컨텍스트마다 용어 정의가 흐려져 모델 경계가 모호해지고 잘못된 통합으로 이어집니다. 그래서 용어 사전을 만들고 코드 이름을 업무 언어와 일치시켜 언어를 일관되게 유지해야 합니다."},
  {"id":"sc-arch-31","cat":"ARCH","level":"중급","q":"분산 트랜잭션에서 2PC 대신 SAGA를 쓰는 이유는 무엇이고, 코레오그래피와 오케스트레이션은 어떻게 다른가요?","a":"2PC는 모든 참여 서비스를 묶어 잠그므로 가용성이 떨어지고 한 노드 장애가 전체를 막아 분산 환경에서 확장에 불리합니다. SAGA는 로컬 트랜잭션을 이어붙이고 실패 시 보상 트랜잭션으로 되돌려 최종 일관성을 달성하는 방식입니다. 코레오그래피는 중앙 조정자 없이 각 서비스가 이벤트를 주고받아 흐름이 자율적으로 이어지는 방식이고, 오케스트레이션은 중앙 오케스트레이터가 단계를 명령·조율하는 방식입니다. 흐름이 단순하면 코레오그래피, 복잡하고 추적이 중요하면 오케스트레이션이 유리합니다."},
  {"id":"sc-arch-32","cat":"ARCH","level":"중급","q":"이중 쓰기(dual write) 문제란 무엇이고 Transactional Outbox로 어떻게 해결하나요?","a":"이중 쓰기는 DB 저장과 메시지 발행을 별개로 수행할 때, 하나는 성공하고 다른 하나가 실패해 DB 상태와 발행된 이벤트가 불일치하는 문제입니다. Transactional Outbox는 비즈니스 변경과 이벤트(outbox 레코드)를 같은 @Transactional, 같은 DB 트랜잭션 안에 함께 커밋해 원자성을 보장하고, 이후 별도 릴레이/스케줄러가 outbox를 폴링해 메시지 브로커로 발행합니다. 발행은 at-least-once라 중복이 생길 수 있으므로 컨슈머는 멱등하게 처리해야 합니다."},
  {"id":"sc-arch-33","cat":"ARCH","level":"심화","q":"메시지 시스템에서 exactly-once가 왜 어려우며, 컨슈머 멱등성이 왜 필요한가요?","a":"네트워크 재시도·장애·재처리 때문에 메시지 전달은 현실적으로 at-least-once로 귀결되어, 같은 메시지가 두 번 이상 도착할 수 있어 진정한 exactly-once 전달은 매우 어렵습니다. Outbox 같은 패턴도 at-least-once를 보장할 뿐입니다. 그래서 중복 수신을 전제로, 컨슈머가 같은 메시지를 여러 번 받아도 결과가 한 번 처리한 것과 같도록 멱등성을 갖춰야 합니다. 처리 이력이나 유니크 제약으로 중복을 걸러 '효과상 한 번'을 달성하는 것이 실무적 해법입니다."},
  {"id":"sc-arch-34","cat":"ARCH","level":"중급","q":"POST 요청에 멱등성을 구현하려면 어떻게 하고, 무엇을 저장·제약해야 하나요?","a":"GET/PUT/DELETE는 본질적으로 멱등하지만 POST는 그렇지 않으므로 Idempotency-Key를 클라이언트가 보내게 합니다. 서버는 그 키에 유니크 제약을 걸어 처리 이력을 저장하고, 같은 키로 또 들어오면 새로 처리하지 않고 기존 결과를 반환합니다. 예를 들어 결제 POST에서 키를 유니크 컬럼으로 두면 두 번 호출돼도 한 번만 처리되고, 동시 중복 요청은 유니크 제약 위반으로 차단됩니다. 핵심은 키 저장 + 유니크 제약 + 기존 결과 반환입니다."},
  {"id":"sc-arch-35","cat":"ARCH","level":"심화","q":"CQRS와 이벤트 소싱은 어떤 이점이 있고, 단순 CRUD에는 왜 과한가요?","a":"CQRS는 명령과 조회 모델을 분리해 읽기 화면에 최적화된 별도 조회 모델을 두고 최종 일관성으로 갱신하는 방식이며, 이벤트 소싱은 상태를 이벤트의 누적으로 저장해 감사 이력과 과거 상태 재구성에 강합니다. 대신 모델 이중화, 동기화, 최종 일관성으로 인한 복잡도가 큽니다. 단순 CRUD는 읽기·쓰기 모델이 거의 같고 감사·재구성 요구도 없어, 이 패턴을 도입하면 얻는 것 없이 운영·정합성 복잡도만 늘어 과합니다."},
  {"id":"sc-arch-36","cat":"ARCH","level":"중급","q":"캐시 스탬피드(thundering herd)란 무엇이고, 캐시 무효화가 왜 어렵나요?","a":"캐시 스탬피드는 인기 키가 만료된 순간 다수 요청이 동시에 캐시 미스를 맞아 원본 DB로 한꺼번에 몰리는 현상입니다. 완화책으로 TTL에 지터를 줘 만료를 분산하고, single-flight로 같은 키 재계산을 한 요청만 수행하게 묶습니다. 캐시 무효화가 어려운 이유는 look-aside/write-through/write-back마다 원본과 캐시의 일관성 보장 시점이 다르고, 갱신·삭제 타이밍을 놓치면 stale 데이터가 남기 때문입니다. 그래서 무효화 전략과 일관성 수준을 신중히 선택해야 합니다."},
  {"id":"sc-arch-37","cat":"ARCH","level":"중급","q":"서킷 브레이커의 세 가지 상태를 설명하고, 재시도를 멱등성과 반드시 함께 다뤄야 하는 이유를 말씀해 주세요.","a":"서킷 브레이커는 Closed(정상 통과), Open(실패 임계 초과로 즉시 차단해 장애 전파를 막음), Half-Open(일정 시간 후 일부 요청만 흘려보내 회복 여부를 시험) 세 상태를 가지며, Half-Open에서 성공하면 Closed로, 실패하면 다시 Open으로 갑니다. 재시도는 지수 백오프와 함께 쓰되 반드시 멱등성과 같이 다뤄야 합니다. 멱등하지 않은 작업을 재시도하면 결제 중복 같은 부작용이 누적되기 때문에, 멱등 키나 처리 이력으로 중복을 흡수한 위에서만 재시도가 안전합니다. Resilience4j 같은 라이브러리로 구현합니다."},
  {"id":"sc-arch-38","cat":"ARCH","level":"중급","q":"하위 호환을 깨지 않으면서 API를 진화시키려면 어떻게 하며, 버저닝 방식들의 장단점은 무엇인가요?","a":"기존 클라이언트를 깨지 않으려면 필드 추가는 선택적으로 하고, 필드 삭제·의미 변경 같은 호환 깨는 변경은 새 버전으로 분리합니다. 버저닝은 URI 방식(/v1/...)이 명시적이고 캐싱·라우팅이 쉽지만 URL이 버전으로 오염되고, 헤더/미디어타입 방식은 URL은 깨끗하나 가시성이 낮고 디버깅이 번거롭습니다. 핵심은 호환을 깨지 않는 진화를 우선하고, 불가피할 때만 버전을 올리며 구버전 지원 기간과 폐기 정책을 함께 정하는 것입니다."},
  {"id":"sc-arch-39","cat":"ARCH","level":"심화","q":"분산 시스템에서 하나의 요청이 여러 서비스를 거칠 때 장애를 어떻게 추적하나요?","a":"분산 트레이싱으로 요청 단위의 trace와 각 구간의 span을 연결하고, correlation ID(상관 ID)를 서비스 간에 전파해 한 요청이 거친 모든 서비스의 로그를 한 줄기로 묶습니다. 여기에 구조화 로깅과 RED/USE 같은 메트릭을 더하면 어느 구간에서 지연·오류가 났는지 짚을 수 있습니다. OpenTelemetry나 Micrometer Tracing으로 trace/span을 계측하면, 어떤 서비스의 어느 호출에서 병목이나 실패가 발생했는지 추적할 수 있습니다."},
  {"id":"sc-java-1","cat":"JAVA","level":"중급","q":"HashMap이 리사이즈(resize)를 수행하는 조건은 무엇이고, capacity가 항상 2의 거듭제곱으로 유지되는 이유는 무엇인가요?","a":"기본 capacity 16, load factor 0.75 기준으로 size가 임계값(capacity*0.75)을 초과하면 capacity를 2배로 늘리고 전체 엔트리를 재해시(rehash)합니다. capacity를 2의 거듭제곱으로 두는 이유는 버킷 인덱스를 hash & (capacity-1) 비트 연산으로 빠르게 계산하기 위해서입니다. 이 마스킹은 capacity가 2의 거듭제곱일 때만 모듈로 연산과 동일하게 동작해 하위 비트를 균등하게 인덱스로 매핑합니다."},
  {"id":"sc-java-2","cat":"JAVA","level":"심화","q":"HashMap에서 버킷의 연결 리스트가 레드블랙 트리로 변환되는 정확한 조건 두 가지는 무엇이고, capacity가 64 미만일 때는 대신 어떤 일이 일어나나요?","a":"한 버킷의 노드 수가 TREEIFY_THRESHOLD(8) 이상이면서 동시에 전체 테이블 capacity가 MIN_TREEIFY_CAPACITY(64) 이상일 때 연결 리스트가 Red-Black Tree로 변환되어 해당 버킷 탐색이 최악 O(n)에서 O(log n)으로 개선됩니다. capacity가 64 미만이면 트리화 대신 리사이즈를 수행해 버킷을 분산시킵니다. 반대로 리사이즈나 제거로 노드 수가 UNTREEIFY_THRESHOLD(6) 이하가 되면 다시 연결 리스트로 untreeify됩니다. JDK 17에서도 동일합니다."},
  {"id":"sc-java-3","cat":"JAVA","level":"기본","q":"equals를 재정의할 때 hashCode도 반드시 함께 재정의해야 하는 이유를 HashMap 동작과 연결해 설명해 주세요.","a":"HashMap/HashSet은 먼저 키의 hashCode로 버킷을 찾고 그 안에서 equals로 키를 최종 구분합니다. equals만 재정의하고 hashCode를 그대로 두면 논리적으로 같은 두 객체가 서로 다른 hashCode를 가져 다른 버킷으로 가기 때문에 put한 값을 get으로 못 찾는 버그가 납니다. equals 규약상 equals가 true인 두 객체는 hashCode도 반드시 같아야 한다는 것이 바로 이 이유입니다. (역은 성립하지 않아 hashCode가 같아도 equals는 다를 수 있고, 이것이 해시 충돌입니다.)"},
  {"id":"sc-java-4","cat":"JAVA","level":"중급","q":"제네릭의 타입 소거(type erasure) 때문에 런타임에 할 수 없는 연산을 세 가지 들어 주세요.","a":"제네릭 타입 정보는 컴파일 시 제거되어 런타임엔 raw type(또는 bound)만 남기 때문에, new T[] 같은 타입 파라미터 배열 생성, T.class 같은 타입 파라미터의 클래스 리터럴 접근, instanceof List<String> 같은 매개변수화 타입에 대한 instanceof 검사가 불가능합니다. 같은 이유로 List<String>과 List<Integer>는 런타임 getClass()가 동일합니다."},
  {"id":"sc-java-5","cat":"JAVA","level":"중급","q":"PECS 원칙이 무엇이고, ? extends T와 ? super T는 각각 언제 쓰나요?","a":"PECS는 Producer-Extends, Consumer-Super의 약자입니다. 제네릭은 기본적으로 무공변(invariant)이라 List<String>은 List<Object>의 하위 타입이 아닌데, 와일드카드로 유연성을 줍니다. 데이터를 꺼내 읽는 생산자(producer)에는 상한 경계 ? extends T를, 데이터를 집어넣는 소비자(consumer)에는 하한 경계 ? super T를 씁니다. 예를 들어 copy(List<? super T> dst, List<? extends T> src)에서 src는 읽기, dst는 쓰기입니다. (Kotlin은 같은 개념을 선언 지점 변성 out/in으로 표현하고, Java는 사용 지점 와일드카드로 표현합니다.)"},
  {"id":"sc-java-6","cat":"JAVA","level":"중급","q":"fail-fast 이터레이터가 무엇이고, 컬렉션을 순회하는 중에 안전하게 원소를 삭제하려면 어떻게 해야 하나요?","a":"fail-fast는 순회 도중 컬렉션의 구조가 변경되면 modCount와 expectedModCount 불일치를 감지해 ConcurrentModificationException을 던지는 동작입니다. 다만 best-effort라 항상 보장되지는 않습니다. 순회 중 삭제는 컬렉션의 remove가 아니라 Iterator.remove()를 사용해야 안전합니다. 참고로 ConcurrentHashMap이나 CopyOnWriteArrayList의 이터레이터는 예외를 던지지 않는 fail-safe(약한 일관성)입니다."},
  {"id":"sc-java-7","cat":"JAVA","level":"심화","q":"Java 9 이후(JDK 17 포함)에서 + 연산자를 통한 문자열 연결은 무엇으로 컴파일되나요? 항상 StringBuilder가 쓰이나요?","a":"아닙니다. Java 8까지는 컴파일러가 한 표현식 내 + 연결을 StringBuilder로 변환했지만, Java 9부터(JEP 280) invokedynamic + StringConcatFactory 호출로 컴파일됩니다. JDK 17도 동일하므로 항상 StringBuilder가 쓰이는 것은 아닙니다. 다만 반복(루프)을 통한 누적 연결은 여전히 매 반복마다 새 객체가 생기므로 StringBuilder를 직접 쓰는 것이 권장됩니다."},
  {"id":"sc-java-8","cat":"JAVA","level":"중급","q":"Java record와 Kotlin data class의 차이를 두 가지 들어 주세요.","a":"첫째, 불변 강제 정도가 다릅니다. record는 모든 컴포넌트가 final로 불변이 강제되지만, data class는 var 프로퍼티도 허용해 가변일 수 있습니다. 둘째, 생성 멤버가 다릅니다. record는 정규(canonical) 생성자와 위치 기반 접근자, equals/hashCode/toString을 자동 생성하지만 copy나 componentN은 없는 반면, data class는 거기에 더해 copy()와 구조 분해용 componentN을 추가로 생성합니다. 또한 record는 다른 클래스를 상속할 수 없는 제약도 있습니다."},
  {"id":"sc-java-9","cat":"JAVA","level":"중급","q":"Java와 Kotlin의 null 처리 차이를 컴파일 타임 보장 관점에서 설명해 주세요.","a":"Java는 모든 참조 타입이 null을 허용해서 컴파일러가 null을 막지 못하고 NPE는 런타임에야 드러납니다. Kotlin은 타입 수준에서 nullable(String?)과 non-null(String)을 구분해 컴파일 타임에 null 위험을 차단하고, 안전 호출 ?., 엘비스 ?:, 비널 단언 !! 같은 연산자를 제공합니다. 다만 Java에서 넘어온 타입은 플랫폼 타입(String!)이라 nullable 여부가 불명확해 컴파일러가 null 검사를 강제하지 못하므로 interop 경계에서 주의해야 합니다."},
  {"id":"sc-java-10","cat":"JAVA","level":"심화","q":"Kotlin엔 checked exception이 없다는 게 무슨 뜻이고 Java interop에서 어떤 문제가 되며, @Throws의 역할은 무엇인가요?","a":"Java는 checked exception을 throws로 시그니처에 선언하고 호출부의 try-catch나 throws 처리를 컴파일러가 강제합니다. Kotlin엔 checked exception 개념 자체가 없어 모든 예외가 unchecked처럼 다뤄지고 throws 강제가 사라집니다. 그래서 Kotlin 함수를 Java에서 호출하면 어떤 체크 예외가 나는지 시그니처에 드러나지 않고 catch 강제도 사라집니다. @Throws를 붙이면 Kotlin 함수에 checked 시그니처를 명시해 Java 호출부에서 예외 처리가 강제되도록 만들 수 있습니다."},
  {"id":"sc-java-11","cat":"JAVA","level":"기본","q":"Kotlin의 data class와 Java record의 차이 두 가지는 무엇인가요?","a":"첫째, data class는 var 프로퍼티를 허용해 가변일 수 있지만 record는 모든 필드가 final로 불변이 강제됩니다. 둘째, data class는 copy()와 구조 분해용 componentN을 추가로 생성하지만 record는 이를 제공하지 않습니다. 또 record는 다른 클래스를 상속할 수 없는 제약이 있습니다. 둘 다 값 객체를 간결하게 만든다는 목적은 같지만 불변 강제 강도와 copy 지원에서 차이가 납니다."},
  {"id":"sc-java-12","cat":"JAVA","level":"중급","q":"Kotlin의 플랫폼 타입(platform type)이 무엇이고 왜 위험한가요?","a":"플랫폼 타입은 Java 코드에서 넘어온, nullable인지 non-null인지 Kotlin 컴파일러가 알 수 없는 타입으로 String! 처럼 표기됩니다. Kotlin은 이 타입에 대해 null 검사를 강제하지 않기 때문에, 실제로는 null이 올 수 있는데도 non-null처럼 다루다가 런타임 NPE가 날 수 있어 위험합니다. 그래서 Java interop 경계에서는 ?. 나 ?: 같은 방어 코드나 명시적 nullable 선언을 넣어 주는 것이 안전합니다."},
  {"id":"sc-java-13","cat":"JAVA","level":"심화","q":"Kotlin 확장 함수(extension function)가 오버라이드되지 않고 정적 디스패치되는 이유는 무엇인가요?","a":"확장 함수는 멤버처럼 호출되지만 실제로는 리시버를 첫 인자로 받는 static 메서드로 컴파일됩니다. 따라서 호출 시 실행 시점의 실제 객체 타입이 아니라 선언된 정적 타입을 기준으로 어떤 함수를 부를지 결정되는 정적 디스패치로 동작합니다. 가상 메서드 테이블을 통한 동적 디스패치가 아니므로 오버라이드(가상 호출)의 대상이 될 수 없습니다."},
  {"id":"sc-java-14","cat":"JAVA","level":"심화","q":"Kotlin의 inline 함수가 해결하는 비용은 무엇이고, crossinline이 필요한 경우는 언제인가요?","a":"고차 함수에 람다를 넘기면 람다마다 객체 생성과 호출 오버헤드가 생기는데, inline 함수는 호출부에 함수 본문과 람다를 인라인해 이 비용을 제거하고 람다 안에서 비지역 반환(non-local return)도 가능하게 합니다. crossinline은 인라인은 하되 그 람다의 비지역 반환을 금지하는 키워드로, 람다를 다른 실행 컨텍스트(예: 다른 객체나 스레드)로 넘겨 거기서 호출할 때 비지역 반환이 안전하지 않으므로 필요합니다. (특정 람다만 인라인에서 제외하려면 noinline을 씁니다.)"},
  {"id":"sc-java-15","cat":"JAVA","level":"기본","q":"Kotlin의 스코프 함수 let, run, with, apply, also를 반환값과 리시버 기준으로 구분해 주세요.","a":"리시버 참조 방식과 반환값으로 나뉩니다. let은 리시버를 it으로 받고 람다 결과를 반환해 주로 nullable 처리에 씁니다. run은 리시버를 this로 받고 람다 결과를 반환합니다. with는 인자를 this로 받고 람다 결과를 반환합니다. apply는 리시버를 this로 받고 객체 자신을 반환해 객체 설정에 적합하고, also는 리시버를 it으로 받고 객체 자신을 반환해 부수효과에 적합합니다. 정리하면 리시버가 this냐 it이냐, 반환이 객체 자신이냐 람다 결과냐로 선택합니다."},
  {"id":"sc-java-16","cat":"JAVA","level":"중급","q":"Kotlin의 by lazy의 기본 thread-safety 모드는 무엇인가요?","a":"by lazy의 기본 모드는 LazyThreadSafetyMode.SYNCHRONIZED입니다. 최초 접근 시 한 번만 초기화 블록을 계산해 캐시하고 이후엔 그 값을 반환하는데, 기본 모드에서는 동기화를 걸어 멀티스레드 환경에서도 단 한 번만 초기화되도록 thread-safe를 보장합니다. 단일 스레드만 접근이 보장된다면 NONE 모드로 동기화 비용을 줄일 수도 있습니다."},
  {"id":"sc-java-17","cat":"JAVA","level":"중급","q":"volatile이 보장하는 것과 보장하지 않는 것을 count++ 예로 설명해 주세요.","a":"volatile은 변수의 가시성과 해당 변수 접근에 대한 재정렬 제한(happens-before)은 보장하지만, 복합 연산의 원자성은 보장하지 않습니다. count++는 읽기-증가-쓰기 세 단계의 복합 연산이라 volatile int라도 두 스레드가 동시에 증가시키면 갱신이 누락되는 race condition이 발생합니다. 따라서 종료 플래그처럼 가시성만 필요한 경우엔 적합하지만, 카운터처럼 복합 연산이 필요한 경우엔 AtomicInteger나 락을 써야 합니다."},
  {"id":"sc-java-18","cat":"JAVA","level":"심화","q":"Java 메모리 모델의 happens-before 관계의 예를 세 가지 들어 주세요.","a":"happens-before는 앞 동작의 메모리 효과가 뒤 동작에서 보인다는 JMM의 부분 순서 규칙입니다. 예로는 모니터 unlock이 이후 같은 모니터의 lock보다 먼저, volatile write가 이후 같은 변수의 read보다 먼저, Thread.start()가 시작된 스레드의 첫 동작보다 먼저 일어납니다. 그 외에도 스레드 종료가 그를 join()한 이후 동작보다 먼저, 같은 스레드 내 프로그램 순서도 happens-before를 형성합니다."},
  {"id":"sc-java-19","cat":"JAVA","level":"중급","q":"synchronized와 ReentrantLock의 차이는 무엇이고, ReentrantLock을 택할 상황은 언제인가요?","a":"synchronized는 객체 모니터를 자동으로 획득/해제하는 재진입 락으로 상호 배제와 가시성을 함께 보장하지만 기능이 제한적입니다. ReentrantLock은 더 유연한 명시적 락으로 타임아웃이 있는 tryLock, 인터럽트 가능한 lockInterruptibly, 공정성(fairness) 옵션, 하나의 락에 여러 Condition을 제공합니다. 그래서 락 획득에 타임아웃을 두거나, 대기 중 인터럽트를 받거나, 공정성이나 다중 조건 변수가 필요할 때 ReentrantLock을 택합니다. 단 반드시 try/finally의 finally에서 unlock해야 합니다."},
  {"id":"sc-java-20","cat":"JAVA","level":"심화","q":"CAS가 무엇이고 Atomic 클래스는 어떻게 lock-free로 동작하나요? ABA 문제는 무엇인가요?","a":"CAS는 Compare-And-Swap의 약자로, 기대값과 현재값이 같을 때만 새 값으로 교체하는 하드웨어 원자 명령입니다. AtomicInteger 같은 클래스는 이 CAS를 써서 락 없이 원자적으로 값을 갱신하고, 실패하면 다시 읽어 재시도하는 lock-free 방식입니다. 경합이 적을 땐 빠르지만 높은 경합에선 spin/재시도 비용이 큽니다. ABA 문제는 값이 A에서 B로 갔다가 다시 A로 돌아오면 CAS가 변하지 않은 것으로 오인하는 문제로, 필요하면 버전을 함께 비교하는 AtomicStampedReference로 해결합니다."},
  {"id":"sc-java-21","cat":"JAVA","level":"중급","q":"데드락 발생 4조건과 실무에서의 회피 전략을 설명해 주세요.","a":"데드락은 둘 이상의 스레드가 서로가 쥔 락을 순환 대기할 때 발생하며 4조건은 상호배제, 점유와 대기(hold and wait), 비선점, 순환대기입니다. 실무 회피 전략으로는 모든 스레드가 락을 같은 순서로 획득하도록 락 순서를 일관화하고, tryLock에 타임아웃을 두어 무한 대기를 끊고, 락 보유 시간과 범위를 최소화하는 방법이 있습니다. 순환대기 조건만 깨도 데드락을 막을 수 있어 락 순서 통일이 가장 현실적입니다."},
  {"id":"sc-java-22","cat":"JAVA","level":"중급","q":"ThreadLocal을 스레드풀에서 쓸 때 반드시 remove()를 호출해야 하는 이유는 무엇인가요?","a":"ThreadLocal은 스레드별로 독립적인 값을 저장하는데, 스레드풀은 작업이 끝나도 스레드를 소멸시키지 않고 재사용합니다. 따라서 이전 작업이 남긴 값이 같은 스레드의 다음 작업에 그대로 보여 데이터가 오염되거나, 참조가 계속 살아 있어 메모리 누수가 발생할 수 있습니다. 이를 막으려면 작업이 끝나는 시점(보통 finally)에 반드시 remove()를 호출해 값을 비워야 합니다."},
  {"id":"sc-java-23","cat":"JAVA","level":"심화","q":"Java 8 이후(JDK 17 포함) ConcurrentHashMap은 동기화 범위를 어떻게 줄였나요? 기존 segment 방식과의 차이는 무엇인가요?","a":"Java 7까지는 맵을 여러 segment로 나누고 segment 단위로 락을 거는 방식이었습니다. Java 8부터(JDK 17 동일)는 segment를 없애고, 빈 버킷에는 CAS로 무락 삽입을 하며 충돌이 있을 때만 해당 버킷의 head 노드에만 synchronized를 거는 세분화된 동기화로 바뀌었습니다. 락 단위가 segment에서 버킷 단위로 더 잘게 쪼개져 동시성과 처리량이 올라갔고, 읽기는 대부분 volatile 읽기로 무락 처리됩니다. 메서드 전체에 락을 거는 Hashtable보다 처리량이 훨씬 높습니다."},
  {"id":"sc-java-24","cat":"JAVA","level":"심화","q":"CompletableFuture와 Kotlin 코루틴은 비동기 합성, 취소, 예외 전파에서 무엇이 다른가요?","a":"CompletableFuture는 스레드풀 위에서 thenApply/thenCompose/thenCombine 같은 콜백을 체이닝하는 방식이라 비동기 흐름이 콜백으로 흩어지고 디스패처 명시가 번거로우며, 구조적 생명주기나 취소 전파가 약해 직접 관리해야 합니다. 코루틴은 suspend 함수로 순차 코드처럼 작성하면서, 부모 스코프가 자식의 완료를 기다리고 취소와 예외를 전파하는 구조적 동시성을 언어 차원에서 보장합니다. 예외 처리도 CompletableFuture는 exceptionally/handle 콜백으로, 코루틴은 구조적 스코프와 SupervisorJob 등으로 다룹니다."},
  {"id":"sc-java-25","cat":"JAVA","level":"중급","q":"코루틴이 스레드보다 경량인 이유를 중단과 스케줄링 관점에서 설명해 주세요.","a":"Java 스레드는 OS 스레드와 1:1로 매핑되어 무겁고 개수에 한계가 있지만, 코루틴은 OS 스레드 위에서 스케줄링되는 경량 단위라 수만~수십만 개까지 만들 수 있습니다. 핵심은 suspend로 중단될 때 스레드를 점유하지 않고 반환한다는 점으로, 적은 수의 스레드로 많은 동시 작업을 처리할 수 있습니다. 컴파일러가 코루틴을 Continuation을 넘기는 CPS 상태 머신으로 변환하기 때문에 중단/재개가 스레드 블로킹 없이 일어납니다."},
  {"id":"sc-java-26","cat":"JAVA","level":"심화","q":"코루틴과 CompletableFuture의 차이를 구조적 동시성, 취소, 예외 전파 관점에서 설명해 주세요.","a":"CompletableFuture는 스레드풀 위 콜백 합성이라 구조적 생명주기가 없어 작업을 직접 추적·취소해야 하고 예외는 exceptionally/handle 콜백으로 다룹니다. 코루틴은 구조적 동시성을 보장해 부모 스코프가 모든 자식의 완료를 기다리고, 부모를 취소하면 자식이 모두 취소되며, 자식의 예외가 부모로 전파됩니다(일반 Job 기준). 덕분에 고아 코루틴이나 누수를 막으면서 suspend로 순차 코드처럼 작성할 수 있다는 점이 가장 큰 차이입니다."},
  {"id":"sc-java-27","cat":"JAVA","level":"중급","q":"구조적 동시성이 보장하는 세 가지는 무엇인가요?","a":"첫째 완료 대기로, 부모 스코프는 모든 자식 코루틴이 끝나야 완료됩니다. 둘째 취소 전파로, 부모를 취소하면 모든 자식이 함께 취소됩니다. 셋째 예외 전파로, 일반 Job에서는 자식의 예외가 부모로 전파됩니다. 이 세 가지 덕분에 고아 코루틴이나 누수 없이 코루틴들의 생명주기를 부모가 책임지고 관리할 수 있습니다."},
  {"id":"sc-java-28","cat":"JAVA","level":"심화","q":"협조적 취소(cooperative cancellation)란 무엇이며, CPU 바운드 루프에서 취소를 보장하려면 어떻게 해야 하나요?","a":"코루틴 취소는 스레드를 강제로 중단하는 게 아니라 협조적입니다. kotlinx.coroutines의 suspend 지점들이 취소 여부를 확인해 CancellationException을 던지는 방식이라, suspend 지점이 없는 CPU 바운드 루프는 cancel()을 호출해도 멈추지 않습니다. 이런 루프에서 취소를 보장하려면 isActive를 확인하거나 ensureActive(), yield() 같은 호출을 루프 안에 넣어 취소 신호를 확인하게 해야 합니다. Java의 Thread.interrupt()도 인터럽트 플래그를 코드가 확인해야 하는 협조적 방식이라는 점에서 유사합니다."},
  {"id":"sc-java-29","cat":"JAVA","level":"중급","q":"Job과 SupervisorJob의 예외 전파 차이는 무엇인가요?","a":"일반 Job에서는 자식 코루틴 하나가 실패하면 그 예외가 부모로 전파되어 부모와 형제 코루틴까지 모두 취소됩니다. SupervisorJob이나 supervisorScope에서는 한 자식의 실패가 형제나 부모로 전파되지 않아 다른 자식들은 독립적으로 계속 실행됩니다. 그래서 서로 독립적인 작업들을 한 스코프에서 돌리되 하나가 실패해도 나머지를 살리고 싶을 때 SupervisorJob을 씁니다."},
  {"id":"sc-java-30","cat":"JAVA","level":"중급","q":"launch와 async의 반환 타입과 예외 전달 시점 차이는 무엇인가요?","a":"launch는 결과가 없는 fire-and-forget 작업으로 Job을 반환하고 예외가 발생하면 즉시 전파됩니다. async는 결과가 있는 작업으로 Deferred를 반환하고 await()로 결과를 받는데, 예외도 await() 호출 시점에 던져집니다. 그래서 병렬 작업은 async 두 개를 띄워 각각 await로 결과와 예외를 받고, 결과가 필요 없는 작업은 launch를 씁니다."},
  {"id":"sc-java-31","cat":"JAVA","level":"심화","q":"cold Flow와 hot 스트림인 StateFlow/SharedFlow의 차이는 무엇이고, StateFlow의 conflation 기준은 무엇인가요?","a":"cold Flow는 collect할 때마다 producer 블록이 처음부터 다시 실행되며, terminal 연산인 collect를 호출하기 전엔 아무 일도 일어나지 않습니다. StateFlow와 SharedFlow는 hot 스트림이라 수집자 유무와 무관하게 활성입니다. StateFlow는 항상 현재 값 1개를 보유하고 초기값이 필수이며 새 구독자에 최신값 1개를 replay하는데, 새 값이 이전 값과 equals로 같으면 방출을 생략하는 conflation이 동작합니다. SharedFlow는 다수 구독자에 브로드캐스트하며 replay 버퍼 등을 설정할 수 있고 초기값이나 기본 conflation은 없습니다."},
  {"id":"sc-java-32","cat":"JAVA","level":"중급","q":"Spring Boot 3.x에서 javax에서 jakarta로의 전환이 무엇을 의미하고, 무엇이 깨지나요?","a":"Spring Boot 3.x와 Spring Framework 6.x는 Java EE에서 Jakarta EE로 전환하면서 javax.* 패키지가 jakarta.*로 바뀝니다. 예를 들어 javax.persistence가 jakarta.persistence로, javax.servlet이 jakarta.servlet으로, javax.validation이 jakarta.validation으로 변경됩니다. 베이스라인 JDK도 17입니다. 그래서 여전히 javax 패키지에 의존하는 구버전 라이브러리는 호환되지 않아 깨지므로 jakarta 기반으로 업그레이드된 버전을 써야 합니다."},
  {"id":"sc-java-33","cat":"JAVA","level":"심화","q":"Servlet 컨테이너의 thread-per-request 모델과 WebFlux의 Netty 이벤트 루프 모델의 동시성 차이와 트레이드오프는 무엇인가요?","a":"기본 Spring MVC는 Tomcat 같은 Servlet 컨테이너 위에서 요청 1건이 스레드 1개를 점유하는 thread-per-request 모델이라 블로킹이 자연스럽지만 동시성 한계가 스레드풀 크기에 묶입니다. WebFlux는 Netty 이벤트 루프 기반으로 적은 스레드로 많은 연결을 논블로킹 처리하며 Reactor의 Mono/Flux를 씁니다. 트레이드오프는 WebFlux가 효과를 보려면 DB 호출 등 전체 스택이 논블로킹이어야 한다는 점으로, 한 군데라도 블로킹이 있으면 이벤트 루프가 막혀 오히려 손해입니다. (JDK 21+ 가상 스레드는 thread-per-request의 블로킹 비용을 줄이는 또 다른 길이지만 JDK 17엔 없습니다.)"},
  {"id":"sc-java-34","cat":"JAVA","level":"중급","q":"Spring Boot가 기본적으로 CGLIB 프록시를 쓰는 이유(proxyTargetClass=true)와 JDK 동적 프록시와의 차이는 무엇인가요?","a":"JDK 동적 프록시는 인터페이스 기반이라 타깃이 인터페이스를 구현해야 하고 인터페이스 타입으로 프록시를 만듭니다. CGLIB는 타깃 클래스를 상속한 서브클래스로 프록시를 만들어 인터페이스가 없어도 동작하지만, final 클래스나 final 메서드는 오버라이드할 수 없어 프록시가 불가능합니다. Spring Boot는 기본적으로 proxyTargetClass=true로 설정해 인터페이스 유무와 무관하게 CGLIB를 사용하며, 이는 인터페이스가 없는 구체 클래스 빈도 일관되게 프록시할 수 있게 해 줍니다. Boot 3.x도 동일합니다."},
  {"id":"sc-java-35","cat":"JAVA","level":"심화","q":"self-invocation에서 @Transactional이 적용되지 않는 이유를 프록시로 설명하고, private이나 final 메서드는 왜 안 되는지도 설명해 주세요.","a":"@Transactional은 빈을 감싼 AOP 프록시가 트랜잭션을 시작·커밋하는 방식으로 동작합니다. 같은 빈 안에서 this로 다른 메서드를 직접 호출하면 프록시를 거치지 않고 실제 객체의 메서드를 바로 부르기 때문에 트랜잭션 어드바이스가 적용되지 않습니다(self-invocation). 또 Spring 기본인 CGLIB 프록시는 서브클래스의 메서드 오버라이드로 동작하는데, private/final/static 메서드는 오버라이드할 수 없어 어드바이스를 걸 수 없습니다. 그래서 트랜잭션 메서드는 public으로 두고, 내부 호출 문제는 빈을 분리하거나 자기 자신을 주입해 프록시를 거치게 해결합니다."},
  {"id":"sc-java-36","cat":"JAVA","level":"중급","q":"@Transactional의 기본 롤백 규칙은 무엇이고 이를 바꾸는 방법은 무엇인가요? Kotlin에선 왜 체감이 다를 수 있나요?","a":"기본적으로 unchecked 예외(RuntimeException, Error)와 그 하위에서만 롤백되고, checked 예외에는 롤백하지 않고 커밋됩니다. checked 예외에도 롤백하려면 rollbackFor를 지정하고, 반대로 특정 예외를 롤백에서 제외하려면 noRollbackFor를 씁니다. 또 예외를 메서드 안에서 잡고 다시 던지지 않으면 프록시가 예외를 못 봐 롤백이 안 됩니다. Kotlin은 checked exception 개념이 없어 모든 예외가 Runtime 계열처럼 다뤄지므로, Java에서 checked로 커밋되던 상황이 Kotlin에선 롤백되는 식으로 체감이 다를 수 있습니다."},
  {"id":"sc-java-37","cat":"JAVA","level":"중급","q":"Spring Boot 2.6+ 및 3.x가 순환참조를 기본적으로 금지하는 이유와 우회 옵션은 무엇인가요?","a":"A와 B가 서로 생성자 주입으로 의존하는 순환은 기동 시 BeanCurrentlyInCreationException으로 실패하는데, 순환참조는 보통 책임 분리가 안 된 설계 문제의 신호라 Spring Boot 2.6+와 3.x는 이를 기본 금지로 바꿨습니다. 우회 옵션으로 spring.main.allow-circular-references=true가 있지만 권장되지 않고, @Lazy로 한쪽 주입을 지연시키거나 세터/필드 주입을 쓰는 임시방편도 있습니다. 근본 해결은 의존 방향을 재설계해 순환을 없애는 것입니다."},
  {"id":"sc-java-38","cat":"JAVA","level":"심화","q":"JPA 영속성 컨텍스트의 1차 캐시, 쓰기 지연, dirty checking을 각각 설명하고, flush가 일어나는 시점 세 가지와 flush가 1차 캐시를 비우는지도 답해 주세요.","a":"1차 캐시는 엔티티를 PK 기준으로 관리해 같은 영속성 컨텍스트 내에서 같은 PK 조회 시 동일 인스턴스를 반환합니다. 쓰기 지연은 INSERT/UPDATE/DELETE를 모았다가 flush 때 한꺼번에 SQL을 보내는 것입니다. dirty checking은 영속 상태 엔티티의 스냅샷과 현재 값을 비교해 변경을 감지하고 flush 때 자동으로 UPDATE를 발행하는 것입니다. flush는 트랜잭션 커밋 직전, JPQL/네이티브 쿼리 실행 직전(기본 FlushMode AUTO), em.flush() 명시 호출 시 일어납니다. flush는 변경을 DB에 동기화할 뿐 1차 캐시를 비우지(clear) 않습니다."},
  {"id":"sc-java-39","cat":"JAVA","level":"심화","q":"N+1 문제가 발생하는 원리와 fetch join으로 해결되는 이유는 무엇이고, OSIV가 기본 true일 때의 장점과 트레이드오프는 무엇인가요?","a":"지연 로딩(LAZY) 연관은 프록시로 두고 실제 접근 시 쿼리를 날리는데, 목록을 순회하며 각 엔티티의 연관을 건마다 조회하면 목록 조회 1번에 더해 N번이 추가로 나가는 N+1이 발생합니다. fetch join(JPQL join fetch)은 한 번의 JOIN 쿼리로 연관까지 즉시 로딩해 추가 쿼리를 없애 줍니다(@EntityGraph나 @BatchSize도 대안). OSIV는 Spring Boot에서 기본 true(spring.jpa.open-in-view)로, 영속성 컨텍스트를 컨트롤러와 뷰 렌더링까지 열어 둬 그 시점의 지연 로딩이 동작하는 장점이 있지만, DB 커넥션을 요청 끝까지 점유해 thread-per-request 모델에서 커넥션 점유 시간이 길어지는 트레이드오프가 있습니다. 트래픽이 큰 서비스는 false로 끄고 트랜잭션 안에서 fetch join으로 처리하는 것을 고려합니다."}
);
